                                        <div className="flex-1 font-bold text-zinc-800 text-xl leading-snug"><EditableText value={safeText(item)} tag="span" /></div>
                                    </div>
                                ))}
                            </div>
                        )}
                    </EditableElement>
                ))}
            </div>
        </div>
    );
};

