        const base64Data = params.image.replace(/^data:image\/(png|jpeg|jpg|webp);base64,/, "").trim();
        parts.push({ 
            inlineData: { 
                mimeType: params.mimeType || 'image/jpeg', 
                data: base64Data
            } 
        });
    }
    parts.push({ text: params.prompt });

    const config: any = {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: params.schema,
        temperature: 0.1,
        // Gemini 3.0 Flash için yüksek muhakeme bütçesi (Thinking Multimodal)
        thinkingConfig: { thinkingBudget: 16000 }
    };

    const response = await ai.models.generateContent({
        model: modelName,
        contents: { parts },
        config: config
    });

    if (response.text) return tryRepairJson(response.text);
    throw new Error("AI yanıt üretmedi.");
};

