                                    </div>
                                ))}
                            </div>
                        </div>
                    )}
                </div>

                {/* SAĞ PANEL: KONTROLLER */}
                <div className="lg:col-span-4 flex flex-col gap-6">
                    <div className="bg-white/5 rounded-[3rem] border border-white/5 p-8 flex flex-col shadow-xl">
