import React, { useState, useEffect, useMemo } from 'react';
import { refinePromptWithAI, generateCreativeStudioActivity, analyzeReferenceFiles } from '../../services/generators/creativeStudio';
import { PEDAGOGICAL_LIBRARY, ActivityLibraryItem } from '../../services/generators/promptLibrary';
import { MultimodalFile } from '../../services/geminiClient';
import { EditorPane } from './EditorPane';
import { LibraryPane } from './LibraryPane';
import { ControlPane } from './ControlPane';
import { SmartTooltip } from './components/SmartTooltip';
import { SnippetManagerModal } from './components/SnippetManagerModal';
import { AISnippet, PROFESSIONAL_SNIPPETS } from '../../services/generators/snippetLibrary';

interface CreativeStudioProps {
    onResult: (data: any) => void;
    onCancel: () => void;
}

const THINKING_MESSAGES = [
    "Gemini 3.0 Pro Motoru Hazırlanıyor...",
    "Dosya mimarisi analiz ediliyor...",
    "Pedagojik metodoloji sentezleniyor...",
    "Nöro-mimari düzen tasarlanıyor...",
    "Klinik çeldiriciler kurgulanıyor...",
    "Görsel hiyerarşi optimize ediliyor...",
    "Hemen hemen hazır, son kontroller yapılıyor..."
];

export const CreativeStudio: React.FC<CreativeStudioProps> = ({ onResult, onCancel }) => {
    // Shared State
    const [prompt, setPrompt] = useState("");
    const [difficulty, setDifficulty] = useState("Orta");
    const [itemCount, setItemCount] = useState(8);
    const [isProcessing, setIsProcessing] = useState(false);
    const [isAnalyzingFile, setIsAnalyzingFile] = useState(false);
    const [status, setStatus] = useState("");
    const [statusIndex, setStatusIndex] = useState(0);
    const [activeTab, setActiveTab] = useState<'editor' | 'library'>('editor');

    // Custom Data States
    const [localLibrary, setLocalLibrary] = useState<ActivityLibraryItem[]>([]);
    const [customSnippets, setCustomSnippets] = useState<AISnippet[]>([]);
    const [showSnippetModal, setShowSnippetModal] = useState(false);

    const [hoveredItem, setHoveredItem] = useState<ActivityLibraryItem | null>(null);
    const [mousePos, setMousePos] = useState({ x: 0, y: 0 });
    const [attachedFiles, setAttachedFiles] = useState<MultimodalFile[]>([]);

    // Initial Load
    useEffect(() => {
        const savedLib = localStorage.getItem('custom_pedagogical_lib');
        setLocalLibrary([...PEDAGOGICAL_LIBRARY, ...(savedLib ? JSON.parse(savedLib) : [])]);

        const savedSnippets = localStorage.getItem('custom_ai_snippets_v2');
        if (savedSnippets) setCustomSnippets(JSON.parse(savedSnippets));
    }, []);

    // Thinking Loop
    useEffect(() => {
        let interval: any;
        if (isProcessing) {
            interval = setInterval(() => setStatusIndex(prev => (prev + 1) % THINKING_MESSAGES.length), 4000);
        }
        return () => clearInterval(interval);
    }, [isProcessing]);

    const handleFilesSelect = async (files: FileList) => {
        setIsAnalyzingFile(true);
        setStatus("Dosyalar okunuyor...");
        try {
            const reader = (file: File): Promise<MultimodalFile> => new Promise((res, rej) => {
                const r = new FileReader();
                r.onload = () => res({ data: r.result as string, mimeType: file.type });
                r.onerror = rej;
                r.readAsDataURL(file);
            });
            const newFiles = await Promise.all(Array.from(files).map(reader));
            const combined = [...attachedFiles, ...newFiles];
            setAttachedFiles(combined);
            const analysisResult = await analyzeReferenceFiles(combined, prompt);
            setPrompt(prev => prev.trim() ? `${prev}\n\n---\n\n${analysisResult}` : analysisResult);
            setStatus("Analiz tamamlandı.");
        } catch (e) {
            setStatus("Analiz başarısız.");
        } finally {
            setIsAnalyzingFile(false);
        }
    };

    const handleRefine = async (mode: 'expand' | 'clinical') => {
        setIsProcessing(true);
        try {
            const refined = await refinePromptWithAI(prompt, mode);
            setPrompt(refined);
        } finally { setIsProcessing(false); }
    };

    const handleSaveCustomSnippet = (snippet: AISnippet) => {
        const updated = [...customSnippets, snippet];
        setCustomSnippets(updated);
        localStorage.setItem('custom_ai_snippets_v2', JSON.stringify(updated));
    };

    const handleDeleteCustomSnippet = (id: string) => {
        const updated = customSnippets.filter(s => s.id !== id);
        setCustomSnippets(updated);
        localStorage.setItem('custom_ai_snippets_v2', JSON.stringify(updated));
    };

    const handleGenerate = async () => {
        if (!prompt.trim() && attachedFiles.length === 0) return;
        setIsProcessing(true);
        try {
            const result = await generateCreativeStudioActivity(prompt, { difficulty, itemCount }, attachedFiles);
            onResult(Array.isArray(result) ? result : [result]);
        } catch (e) {
            setStatus("Hata oluştu.");
        } finally {
            setIsProcessing(false);
        }
    };

    // Current Snippets for Editor (Merging System + Custom)
    const activeSnippets = useMemo(() => {
        return [...PROFESSIONAL_SNIPPETS, ...customSnippets].slice(0, 8); // Editor shortcuts limit
    }, [customSnippets]);

    return (
        <div className="max-w-7xl mx-auto w-full font-['Lexend'] relative">
            <SmartTooltip item={hoveredItem} pos={mousePos} />

            {showSnippetModal && (
                <SnippetManagerModal 
                    onClose={() => setShowSnippetModal(false)}
                    customSnippets={customSnippets}
                    onSaveCustom={handleSaveCustomSnippet}
                    onDeleteCustom={handleDeleteCustomSnippet}
                    onSelect={(s) => {
                        setPrompt(prev => prev + "\n\n" + s.value);
                        setShowSnippetModal(false);
                    }}
                />
            )}

            <div className="flex flex-col md:flex-row justify-between items-center mb-8 gap-4 px-4">
                <div>
                    <h2 className="text-4xl font-black tracking-tighter text-white flex items-center gap-3">
                        <i className="fa-solid fa-wand-magic-sparkles text-indigo-500"></i> AI Creative Studio
                    </h2>
                    <p className="text-zinc-500 text-sm mt-1 uppercase tracking-widest font-bold">Klinik Tasarım ve Mimari Klonlama</p>
                </div>
                <div className="flex bg-zinc-900 border border-white/10 p-1.5 rounded-2xl shadow-inner">
                    <button onClick={() => setActiveTab('editor')} className={`px-8 py-2.5 rounded-xl text-xs font-black transition-all ${activeTab === 'editor' ? 'bg-white text-black shadow-xl' : 'text-zinc-500 hover:text-zinc-300'}`}>TASARIMCI</button>
                    <button onClick={() => setActiveTab('library')} className={`px-8 py-2.5 rounded-xl text-xs font-black transition-all ${activeTab === 'library' ? 'bg-white text-black shadow-xl' : 'text-zinc-500 hover:text-zinc-300'}`}>METODOLOJİ BANKASI</button>
                </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-start px-4">
                <div className="lg:col-span-8 flex flex-col gap-6 h-[750px]">
                    {activeTab === 'editor' ? (
                        <EditorPane 
                            prompt={prompt} setPrompt={setPrompt} attachedFiles={attachedFiles}
                            onFilesSelect={handleFilesSelect} onRemoveFile={(idx) => setAttachedFiles(f => f.filter((_, i) => i !== idx))}
                            onRefine={handleRefine} snippets={activeSnippets} isAnalyzing={isAnalyzingFile}
                            onAddSnippet={() => setShowSnippetModal(true)}
                        />
                    ) : (
                        <LibraryPane 
                            items={localLibrary} onAddCustom={() => {}} 
                            onSelect={(item) => { setPrompt(item.basePrompt); setActiveTab('editor'); }}
                            onHover={(item, pos) => { setHoveredItem(item); setMousePos(pos); }}
                        />
                    )}
                </div>

                <div className="lg:col-span-4">
                    <ControlPane 
                        difficulty={difficulty} setDifficulty={setDifficulty}
                        itemCount={itemCount} setItemCount={setItemCount}
                        onGenerate={handleGenerate} onCancel={onCancel}
                        isProcessing={isProcessing} isAnalyzing={isAnalyzingFile}
                        status={status} statusMessage={THINKING_MESSAGES[statusIndex]}
                    />
                </div>
            </div>
        </div>
    );
};

import { Type } from "@google/genai";
import { generateCreativeMultimodal, MultimodalFile } from '../geminiClient';
import { PEDAGOGICAL_BASE, CLINICAL_DIAGNOSTIC_GUIDE } from './prompts';

/**
 * analyzeReferenceFiles: Yüklenen dosyaları analiz eder ve teknik bir üretim promptu oluşturur.
 */
export const analyzeReferenceFiles = async (files: MultimodalFile[], currentPrompt: string): Promise<string> => {
    const prompt = `
    [GÖREV: PEDAGOJİK MİMARİ ANALİST]
    Ekteki dosyaları (PDF/Görsel) teknik olarak analiz et. 
    Bu dosyaların:
    1. Sayfa düzenini (Layout)
    2. Soru sorma stilini (Matching, Grid, Multiple Choice vb.)
    3. Kullanılan görsel hiyerarşi ve çeldirici mantığını tanımla.

    KULLANICI TERCİHİ: "${currentPrompt}"

    GÖREVİN: Bu dosyaları referans alarak, Bursa Disleksi AI motorunun BİREBİR AYNI KALİTEDE VE YAPIDA bir çıktı üretmesi için gereken DETAYLI TEKNİK PROMPTU OLUŞTUR.

    ÇIKTI KURALI:
    - Sonuç "Bu materyalin yapısını analiz ettim. İşte üretim için teknik plan:" cümlesiyle başlamalı.
    - İçerisinde [MİMARİ], [İÇERİK PLANI], [PEDAGOJİK HEDEF] başlıkları olmalı.
    - SADECE METİN DÖNDÜR.
    `;

    const schema = { 
        type: Type.OBJECT, 
        properties: { 
            analysisPrompt: { type: Type.STRING } 
        }, 
        required: ['analysisPrompt'] 
    };

    const result = await generateCreativeMultimodal({ prompt, schema, files });
    return result.analysisPrompt;
};

/**
 * refinePromptWithAI: Kullanıcının promptunu profesyonel seviyeye taşır.
 */
export const refinePromptWithAI = async (userPrompt: string, mode: 'expand' | 'narrow' | 'clinical'): Promise<string> => {
    const instruction = mode === 'expand' 
        ? "Bu promptu pedagojik derinlik katarak, disleksi dostu materyal üretim kurallarıyla zenginleştir."
        : mode === 'narrow'
        ? "Bu promptu sadeleştir, sadece en temel klinik hedefe odaklan ve netleştir."
        : "Bu prompta klinik tanı kriterleri ekle (reversal errors, phonological gaps vb.).";

    const prompt = `
    [GÖREV: PROMPT MİMARI]
    HAM PROMPT: "${userPrompt}"
    TALİMAT: ${instruction}

    KURAL: Sonuç doğrudan bir yapay zeka modeline talimat olarak gönderilecektir. 
    İçeriğinde "Şunu yap", "Şu formatta olsun" gibi net emirler barındırmalıdır.
    Sadece zenginleştirilmiş metni döndür.
    `;

    const schema = { 
        type: Type.OBJECT, 
        properties: { 
            refined: { type: Type.STRING } 
        }, 
        required: ['refined'] 
    };
    const result = await generateCreativeMultimodal({ prompt, schema });
    return result.refined;
};

/**
 * generateCreativeStudioActivity: Zenginleştirilmiş prompt ve dosyalarla tam layout üretir.
 */
export const generateCreativeStudioActivity = async (enrichedPrompt: string, options: any, files?: MultimodalFile[]) => {
    const prompt = `
    ${PEDAGOGICAL_BASE}
    ${CLINICAL_DIAGNOSTIC_GUIDE}

    GÖREV: NÖRO-MİMARİ ÜRETİM VE KLONLAMA SENTEZİ

    TALİMAT:
    ${enrichedPrompt}

    ANALİZ VE ÜRETİM KRİTERİ:
    1. Ekte PDF veya Görsel varsa; bu dosyaların eğitimsel yaklaşımını, mizanpajını ve zorluk seviyesini referans al.
    2. Yeni üretilecek içerik bu dosyaların kalitesinde ancak tamamen özgün sorularla inşa edilmelidir.
    3. KRİTİK: 'viewBox' alanına sadece "0 0 100 100" yaz. Asla çok büyük sayılar yazma.

    PARAMETRELER:
    - Zorluk: ${options.difficulty}
    - Öğe Sayısı: ${options.itemCount}

    ÇIKTI: Kesinlikle 'layoutArchitecture' formatında ve 'blocks' dizisi içermelidir.
    `;

    const schema = {
        type: Type.OBJECT,
        properties: {
            title: { type: Type.STRING },
            instruction: { type: Type.STRING },
            pedagogicalNote: { type: Type.STRING },
            layoutArchitecture: {
                type: Type.OBJECT,
                properties: {
                    blocks: {
                        type: Type.ARRAY,
                        items: {
                            type: Type.OBJECT,
                            properties: {
                                type: { type: Type.STRING, enum: ['header', 'text', 'grid', 'table', 'svg_shape', 'dual_column', 'image'] },
                                content: { 
                                    type: Type.OBJECT,
                                    properties: {
                                        text: { type: Type.STRING },
                                        cols: { type: Type.INTEGER },
                                        rows: { type: Type.INTEGER },
                                        cells: { type: Type.ARRAY, items: { type: Type.STRING } },
                                        headers: { type: Type.ARRAY, items: { type: Type.STRING } },
                                        data: { type: Type.ARRAY, items: { type: Type.ARRAY, items: { type: Type.STRING } } },
                                        left: { type: Type.ARRAY, items: { type: Type.STRING } },
                                        right: { type: Type.ARRAY, items: { type: Type.STRING } },
                                        prompt: { type: Type.STRING },
                                        viewBox: { type: Type.STRING },
                                        paths: { type: Type.ARRAY, items: { type: Type.STRING } }
                                    }
                                },
                                weight: { type: Type.INTEGER }
                            },
                            required: ['type', 'content']
                        }
                    }
                },
                required: ['blocks']
            }
        },
        required: ['title', 'instruction', 'layoutArchitecture']
    };

    return await generateCreativeMultimodal({ prompt, schema, files });
};

