import { db } from './firebaseClient';
import * as firestore from "firebase/firestore";
import { DynamicActivity, PromptTemplate, PromptSnippet, StaticContentItem, ActivityDraft, PromptVersion } from '../types/admin';
import { UserRole, UserStatus } from '../types/core';
import { generateWithSchema } from './geminiClient';
import { Type } from "@google/genai";

const { collection, doc, getDocs, setDoc, query, where, updateDoc, deleteDoc } = firestore;

export const adminService = {
    // Tüm dinamik aktiviteleri getir
    getAllActivities: async (): Promise<DynamicActivity[]> => {
        try {
            const snapshot = await getDocs(collection(db, "config_activities"));
            return snapshot.docs.map(d => d.data() as DynamicActivity);
        } catch (e) {
            console.error("Dinamik aktiviteler yüklenemedi", e);
            return [];
        }
    },

    // Yeni aktiviteyi sisteme/menüye kaydet
    publishNewActivity: async (activity: DynamicActivity) => {
        const docRef = doc(db, "config_activities", activity.id);
        await setDoc(docRef, {
            ...activity,
            updatedAt: new Date().toISOString()
        }, { merge: true });
    },

    // --- ACTIVITY MANAGEMENT ---
    saveActivity: async (activity: DynamicActivity) => {
        const docRef = doc(db, "config_activities", activity.id);
        await setDoc(docRef, activity, { merge: true });
    },

    // --- PROMPT MANAGEMENT ---
    getAllPrompts: async (): Promise<PromptTemplate[]> => {
        const snapshot = await getDocs(collection(db, "config_prompts"));
        return snapshot.docs.map(d => d.data() as PromptTemplate);
    },

    getInitialPromptForActivity: (id: string) => {
        return `[GÖREV: ${id}]\nSen bir özel eğitim uzmanısın. Disleksi dostu içerik üret.\n\n[MİMARİ DNA]:\n{{blueprint}}`;
    },

    savePrompt: async (prompt: PromptTemplate, note: string): Promise<PromptTemplate> => {
        const newVersion = (prompt.version || 0) + 1;
        const historyItem: PromptVersion = {
            version: newVersion,
            updatedAt: new Date().toISOString(),
            template: prompt.template,
            systemInstruction: prompt.systemInstruction,
            changeLog: note
        };
        const updated: PromptTemplate = {
            ...prompt,
            version: newVersion,
            updatedAt: new Date().toISOString(),
            history: [...(prompt.history || []), historyItem]
        };
        await setDoc(doc(db, "config_prompts", prompt.id), updated);
        return updated;
    },

    testPrompt: async (prompt: PromptTemplate, vars: Record<string, string>) => {
        let appliedTemplate = prompt.template;
        Object.entries(vars).forEach(([k, v]) => {
            appliedTemplate = appliedTemplate.replace(new RegExp(`\\{\\{${k}\\}\\}`, 'g'), v);
        });

        // Use flash model for simulation/test
        return await generateWithSchema(appliedTemplate, { type: Type.OBJECT }, 'gemini-3-flash-preview');
    },

    // --- SNIPPETS ---
    getAllSnippets: async (): Promise<PromptSnippet[]> => {
        const snapshot = await getDocs(collection(db, "config_snippets"));
        return snapshot.docs.map(d => d.data() as PromptSnippet);
    },

    saveSnippet: async (snippet: PromptSnippet) => {
        await setDoc(doc(db, "config_snippets", snippet.id), snippet);
    },

    // --- STATIC CONTENT (CMS) ---
    getAllStaticContent: async (): Promise<StaticContentItem[]> => {
        const snapshot = await getDocs(collection(db, "config_static_content"));
        return snapshot.docs.map(d => d.data() as StaticContentItem);
    },

    saveStaticContent: async (item: StaticContentItem) => {
        await setDoc(doc(db, "config_static_content", item.id), {
            ...item,
            updatedAt: new Date().toISOString()
        });
    },

    // --- USER MANAGEMENT ---
    updateUserRole: async (userId: string, newRole: UserRole) => {
        await updateDoc(doc(db, "users", userId), { role: newRole });
    },

    updateUserStatus: async (userId: string, newStatus: UserStatus) => {
        await updateDoc(doc(db, "users", userId), { status: newStatus });
    },

    // --- DRAFTS (OCR) ---
    getAllDrafts: async (): Promise<ActivityDraft[]> => {
        const snapshot = await getDocs(collection(db, "activity_drafts"));
        return snapshot.docs.map(d => d.data() as ActivityDraft);
    },

    publishDraft: async (draft: ActivityDraft, config: any) => {
        await adminService.publishNewActivity({
            id: draft.id,
            ...config,
            isActive: true,
            isPremium: false,
            updatedAt: new Date().toISOString(),
            engineConfig: { 
                mode: 'ai_only', 
                parameters: { allowDifficulty: true, allowDistraction: true, allowFontSize: true } 
            }
        } as DynamicActivity);
        await deleteDoc(doc(db, "activity_drafts", draft.id));
    },

    deleteDraft: async (id: string) => {
        await deleteDoc(doc(db, "activity_drafts", id));
    }
};

import { Type } from "@google/genai";
import { generateCreativeMultimodal, generateWithSchema, MultimodalFile } from '../geminiClient';
import { PEDAGOGICAL_BASE, CLINICAL_DIAGNOSTIC_GUIDE } from './prompts';

/**
 * generateCreativeStudioActivity: 
 * JSON Repair hatasını önlemek için Type.INTEGER kullanımı ve viewBox kısıtlaması.
 */
export const generateCreativeStudioActivity = async (enrichedPrompt: string, options: any, files?: MultimodalFile[]) => {

    const clinicalDirectives = `
    [KLİNİK PARAMETRELER - KRİTİK]
    1. ZORLUK: ${options.difficulty}. Basitlik ve aşama sayısını buna göre ayarla.
    2. ÇELDİRİCİ: ${options.distractionLevel}. 'high' ise benzer harf/şekil (b-d, m-n) kullan.
    3. TİPOGRAFİ: ${options.fontSizePreference}. 'large' ise metin boyutlarını artır.

    KRİTİK GÖRSEL KURALI: 
    - 'viewBox' her zaman "0 0 100 100" olmalıdır. 
    - ASLA büyük rakamlar (1000000...) kullanma.
    `;

    const prompt = `
    ${PEDAGOGICAL_BASE}
    ${CLINICAL_DIAGNOSTIC_GUIDE}
    ${clinicalDirectives}
    GÖREV: PROFESYONEL EĞİTİM MATERYALİ SENTEZİ
    TALİMAT: ${enrichedPrompt}
    `;

    const schema = {
        type: Type.OBJECT,
        properties: {
            title: { type: Type.STRING },
            instruction: { type: Type.STRING },
            pedagogicalNote: { type: Type.STRING },
            layoutArchitecture: {
                type: Type.OBJECT,
                properties: {
                    blocks: {
                        type: Type.ARRAY,
                        items: {
                            type: Type.OBJECT,
                            properties: {
                                type: { type: Type.STRING, enum: ['header', 'text', 'grid', 'table', 'svg_shape', 'dual_column', 'image'] },
                                content: { 
                                    type: Type.OBJECT,
                                    properties: {
                                        text: { type: Type.STRING },
                                        cols: { type: Type.INTEGER },
                                        rows: { type: Type.INTEGER },
                                        cells: { type: Type.ARRAY, items: { type: Type.STRING } },
                                        headers: { type: Type.ARRAY, items: { type: Type.STRING } },
                                        data: { type: Type.ARRAY, items: { type: Type.ARRAY, items: { type: Type.STRING } } },
                                        left: { type: Type.ARRAY, items: { type: Type.STRING } },
                                        right: { type: Type.ARRAY, items: { type: Type.STRING } },
                                        prompt: { type: Type.STRING },
                                        viewBox: { type: Type.STRING },
                                        paths: { type: Type.ARRAY, items: { type: Type.STRING } }
                                    }
                                },
                                style: {
                                    type: Type.OBJECT,
                                    properties: {
                                        fontSize: { type: Type.INTEGER },
                                        fontWeight: { type: Type.STRING },
                                        textAlign: { type: Type.STRING }
                                    }
                                }
                            },
                            required: ['type', 'content']
                        }
                    }
                },
                required: ['blocks']
            }
        },
        required: ['title', 'instruction', 'layoutArchitecture']
    };

    return await generateCreativeMultimodal({ prompt, schema, files });
};

/* Fix: Implemented missing prompt refinement utility */
export const refinePromptWithAI = async (prompt: string, mode: 'expand' | 'clinical'): Promise<string> => {
    const aiPrompt = `Aşağıdaki promptu ${mode === 'expand' ? 'daha detaylı hale getir' : 'klinik perspektifle zenginleştir'}: ${prompt}`;
    const schema = { 
        type: Type.OBJECT, 
        properties: { refined: { type: Type.STRING } }, 
        required: ['refined'] 
    };
    const result = await generateWithSchema(aiPrompt, schema, 'gemini-3-flash-preview');
    return result.refined;
};

/* Fix: Implemented missing file analysis utility */
export const analyzeReferenceFiles = async (files: MultimodalFile[], currentPrompt: string): Promise<string> => {
    const prompt = `Dosyaları analiz et ve teknik bir taslak çıkar. ${currentPrompt ? `Bağlam: ${currentPrompt}` : ""}`;
    const schema = { 
        type: Type.OBJECT, 
        properties: { analysis: { type: Type.STRING } }, 
        required: ['analysis'] 
    };
    const result = await generateCreativeMultimodal({ prompt, schema, files, useFlash: true });
    return result.analysis;
};

import React, { useState, useMemo, useEffect } from 'react';
import { ActivityType, WorksheetData, Activity, GeneratorOptions, ActivityCategory, ActiveCurriculumSession } from '../types';
import { ACTIVITY_CATEGORIES, ACTIVITIES } from '../constants';
import * as generators from '../services/generators';
import * as offlineGenerators from '../services/offlineGenerators';
import { GeneratorView } from './GeneratorView';
import { statsService } from '../services/statsService';
import { adminService } from '../services/adminService';
import { useStudent } from '../context/StudentContext';

const toPascalCase = (str: string): string => {
    if (!str) return '';
    return str.toLowerCase()
              .split(/[-_ ]+/)
              .map(word => word.charAt(0).toUpperCase() + word.slice(1).toLowerCase())
              .join(' ');
};

interface SidebarProps {
  selectedActivity: ActivityType | null;
  onSelectActivity: (id: ActivityType | null) => void;
  setWorksheetData: (data: WorksheetData) => void;
  setIsLoading: (loading: boolean) => void;
  setError: (error: string | null) => void;
  isLoading: boolean;
  isSidebarOpen: boolean;
  closeSidebar: () => void;
  onAddToHistory: (activityType: ActivityType, data: WorksheetData) => void;
  isExpanded?: boolean;
  onOpenOCR?: () => void;
  onOpenCurriculum?: () => void;
  onOpenReadingStudio?: () => void;
  onOpenMathStudio?: () => void;
  activeCurriculumSession?: ActiveCurriculumSession | null;
}

const Sidebar: React.FC<SidebarProps> = ({
  isSidebarOpen, closeSidebar, selectedActivity, onSelectActivity, setWorksheetData, setIsLoading, setError, isLoading, onAddToHistory, isExpanded = true,
  onOpenOCR, onOpenCurriculum, onOpenReadingStudio, onOpenMathStudio, activeCurriculumSession
}) => {
  const [openCategoryId, setOpenCategoryId] = useState<string | null>(null);
  const { activeStudent } = useStudent();
  const [allActivities, setAllActivities] = useState<Activity[]>(ACTIVITIES);
  const [categories, setCategories] = useState<ActivityCategory[]>(ACTIVITY_CATEGORIES);

  useEffect(() => {
      const loadDynamicResources = async () => {
          try {
              const dynamicActs = await adminService.getAllActivities();
              if (dynamicActs.length === 0) return;

              // 1. Aktivite Listesini Güncelle
              const mappedActs: Activity[] = dynamicActs.map(da => ({
                  id: da.id as any,
                  title: da.title,
                  description: da.description,
                  icon: da.icon,
                  defaultStyle: { columns: 1 }
              }));

              setAllActivities(prev => [...prev, ...mappedActs]);

              // 2. Kategorileri Güncelle (Dinamik aktiviteleri ait oldukları yere ekle)
              setCategories(prev => prev.map(cat => ({
                  ...cat,
                  activities: [...cat.activities, ...dynamicActs.filter(da => da.category === cat.id).map(da => da.id as any)]
              })));

          } catch (e) {
              console.error("Dinamik kaynaklar yüklenemedi");
          }
      };
      loadDynamicResources();
  }, []);

  const handleGenerate = async (options: GeneratorOptions) => {
    if (!selectedActivity) return;
    setIsLoading(true);
    setWorksheetData(null);
    setError(null);

    try {
        let result: WorksheetData | null = null;

        // Eğer seçilen aktivite bir dinamik (Studio) aktivitesiyse özel motoru çalıştır
        if (String(selectedActivity).startsWith('dyn_')) {
            const dynamicAct = (await adminService.getAllActivities()).find(a => a.id === selectedActivity);
            if (dynamicAct?.engineConfig.baseBlueprint) {
                // Dinamik üretim motoru (Creative Studio Engine)
                result = await generators.generateFromRichPrompt(
                    selectedActivity, 
                    dynamicAct.engineConfig.baseBlueprint, 
                    options
                );
            }
        }

        // Değilse standart akış (AI veya Offline)
        if (!result) {
            const pascalCaseName = toPascalCase(selectedActivity).replace(/\s+/g, '');
            const generatorFunctionName = `generate${pascalCaseName}FromAI`;
            const runOfflineGenerator = async () => {
                 const offlineGenerator = (offlineGenerators as any)[`generateOffline${pascalCaseName}`];
                 if (offlineGenerator) return await offlineGenerator(options);
                 throw new Error("Üretim motoru bulunamadı.");
            };

            if (options.mode === 'ai') {
                const onlineGenerator = (generators as any)[generatorFunctionName];
                result = onlineGenerator ? await onlineGenerator(options) : await runOfflineGenerator();
            } else {
                result = await runOfflineGenerator();
            }
        }

        if (result) {
            setWorksheetData(result);
            onAddToHistory(selectedActivity, result);
            statsService.incrementUsage(selectedActivity).catch(console.error);
        }
    } catch (e: any) { 
        setError(e.message); 
    } finally { 
        setIsLoading(false); 
    }
  };

  const categorizedActivities = useMemo(() => {
      return categories.map(category => ({ 
          ...category, 
          items: allActivities.filter(act => category.activities.includes(act.id)) 
      })).filter(c => c.items.length > 0);
  }, [allActivities, categories]);

  return (
    <aside className={`fixed inset-y-0 left-0 z-30 bg-white/95 dark:bg-zinc-900/95 backdrop-blur-xl border-r border-zinc-200 dark:border-zinc-800 transition-all duration-500 ease-in-out flex flex-col h-full md:relative md:translate-x-0 ${isSidebarOpen ? 'translate-x-0 shadow-2xl' : '-translate-x-full md:shadow-none'} ${isExpanded ? 'w-[300px]' : 'w-[70px]'}`}>
        <div className="flex h-full flex-col">
            {selectedActivity ? (
                <GeneratorView 
                    activity={allActivities.find(a => a.id === selectedActivity)!} 
                    onGenerate={handleGenerate} 
                    onBack={() => onSelectActivity(null)} 
                    isLoading={isLoading} 
                    activeCurriculumSession={activeCurriculumSession}
                />
            ) : (
                <nav className="flex-1 overflow-y-auto px-2 py-4 space-y-1 custom-scrollbar">
                    {categorizedActivities.map((category) => {
                        const isOpen = openCategoryId === category.id;
                        return (
                            <div key={category.id}>
                                <button onClick={() => isExpanded && setOpenCategoryId(isOpen ? null : category.id)} className={`w-full flex items-center gap-2 px-3 py-2 rounded-xl transition-all ${isOpen && isExpanded ? 'bg-zinc-800 text-white' : 'hover:bg-zinc-100 text-zinc-600 dark:text-zinc-400'}`}>
                                    <i className={`${category.icon} w-5`}></i>
                                    {isExpanded && <span className="flex-1 text-left text-xs font-black uppercase truncate">{category.title}</span>}
                                </button>
                                {isExpanded && isOpen && (
                                    <div className="pl-6 mt-1 space-y-1">
                                        {category.items.map(activity => (
                                            <button key={activity.id} onClick={() => onSelectActivity(activity.id)} className={`w-full text-left px-3 py-1.5 rounded-lg text-[10px] font-bold transition-all ${selectedActivity === activity.id ? 'bg-indigo-50 text-indigo-700' : 'text-zinc-500 hover:text-zinc-900 hover:bg-zinc-50'}`}>
                                                {activity.title}
                                            </button>
                                        ))}
                                    </div>
                                )}
                            </div>
                        );
                    })}
                </nav>
            )}
        </div>
    </aside>
  );
};

