import React, { useState, useMemo, useEffect } from 'react';
import { ActivityType, WorksheetData, Activity, GeneratorOptions, ActivityCategory, ActiveCurriculumSession } from '../types';
import { ACTIVITY_CATEGORIES, ACTIVITIES } from '../constants';
import * as generators from '../services/generators';
import * as offlineGenerators from '../services/offlineGenerators';
import { GeneratorView } from './GeneratorView';
import { statsService } from '../services/statsService';
import { adminService } from '../services/adminService';
import { useStudent } from '../context/StudentContext';

const toPascalCase = (str: string): string => {
    if (!str) return '';
    return str.toLowerCase()
              .split(/[-_ ]+/)
              .map(word => word.charAt(0).toUpperCase() + word.slice(1).toLowerCase())
              .join(' ');
};

interface SidebarProps {
  selectedActivity: ActivityType | null;
  onSelectActivity: (id: ActivityType | null) => void;
  setWorksheetData: (data: WorksheetData) => void;
  setIsLoading: (loading: boolean) => void;
  setError: (error: string | null) => void;
  isLoading: boolean;
  isSidebarOpen: boolean;
  closeSidebar: () => void;
  onAddToHistory: (activityType: ActivityType, data: WorksheetData) => void;
  isExpanded?: boolean;
  onOpenOCR?: () => void;
  onOpenCurriculum?: () => void;
  onOpenReadingStudio?: () => void;
  onOpenMathStudio?: () => void;
  activeCurriculumSession?: ActiveCurriculumSession | null;
}

const Sidebar: React.FC<SidebarProps> = ({
  isSidebarOpen, closeSidebar, selectedActivity, onSelectActivity, setWorksheetData, setIsLoading, setError, isLoading, onAddToHistory, isExpanded = true,
  onOpenOCR, onOpenCurriculum, onOpenReadingStudio, onOpenMathStudio, activeCurriculumSession
}) => {
  const [openCategoryId, setOpenCategoryId] = useState<string | null>(null);
  const { activeStudent } = useStudent();
  const [allActivities, setAllActivities] = useState<Activity[]>(ACTIVITIES);
  const [categories, setCategories] = useState<ActivityCategory[]>(ACTIVITY_CATEGORIES);

  useEffect(() => {
      const loadDynamicResources = async () => {
          try {
              const dynamicActs = await adminService.getAllActivities();
              if (dynamicActs.length === 0) return;

              // 1. Aktivite Listesini Güncelle
              const mappedActs: Activity[] = dynamicActs.map(da => ({
                  id: da.id as any,
                  title: da.title,
                  description: da.description,
                  icon: da.icon,
                  defaultStyle: { columns: 1 }
              }));

              const mergedActivities = [...ACTIVITIES];
              mappedActs.forEach(ma => {
                  if(!mergedActivities.find(ex => ex.id === ma.id)) {
                      mergedActivities.push(ma);
                  }
              });
              setAllActivities(mergedActivities);

              // 2. Kategorileri Güncelle
              setCategories(prev => prev.map(cat => ({
                  ...cat,
                  activities: [...new Set([...cat.activities, ...dynamicActs.filter(da => da.category === cat.id).map(da => da.id as any)])]
              })));

          } catch (e) {
              console.error("Dinamik kaynaklar yüklenemedi");
          }
      };
      loadDynamicResources();
  }, []);

  const handleGenerate = async (options: GeneratorOptions) => {
    if (!selectedActivity) return;
    setIsLoading(true);
    setWorksheetData(null);
    setError(null);

    try {
        let result: WorksheetData | null = null;

        // Dinamik Aktivite Kontrolü
        if (String(selectedActivity).startsWith('dyn_')) {
            const dynamicAct = (await adminService.getAllActivities()).find(a => a.id === selectedActivity);
            if (dynamicAct?.engineConfig.baseBlueprint) {
                result = await generators.generateFromRichPrompt(
                    selectedActivity, 
                    dynamicAct.engineConfig.baseBlueprint, 
                    options
                );
            }
        }

        // Standart Akış
        if (!result) {
            const pascalCaseName = toPascalCase(selectedActivity).replace(/\s+/g, '');
            const generatorFunctionName = `generate${pascalCaseName}FromAI`;
            const runOfflineGenerator = async () => {
                 const offlineGenerator = (offlineGenerators as any)[`generateOffline${pascalCaseName}`];
                 if (offlineGenerator) return await offlineGenerator(options);
                 throw new Error("Üretim motoru bulunamadı.");
            };

            if (options.mode === 'ai') {
                const onlineGenerator = (generators as any)[generatorFunctionName];
                result = onlineGenerator ? await onlineGenerator(options) : await runOfflineGenerator();
            } else {
                result = await runOfflineGenerator();
            }
        }

        if (result) {
            setWorksheetData(result);
            onAddToHistory(selectedActivity, result);
            statsService.incrementUsage(selectedActivity).catch(console.error);
        }
    } catch (e: any) { 
        setError(e.message); 
    } finally { 
        setIsLoading(false); 
    }
  };

  const categorizedActivities = useMemo(() => {
      return categories.map(category => ({ 
          ...category, 
          items: allActivities.filter(act => category.activities.includes(act.id)) 
      })).filter(c => c.items.length > 0);
  }, [allActivities, categories]);

  return (
    <aside className={`fixed inset-y-0 left-0 z-30 bg-white/95 dark:bg-zinc-900/95 backdrop-blur-xl border-r border-zinc-200 dark:border-zinc-800 transition-all duration-500 ease-in-out flex flex-col h-full md:relative md:translate-x-0 ${isSidebarOpen ? 'translate-x-0 shadow-2xl' : '-translate-x-full md:shadow-none'} ${isExpanded ? 'w-[300px]' : 'w-[70px]'}`}>
        <div className="flex h-full flex-col">
            {selectedActivity ? (
                <GeneratorView 
                    activity={allActivities.find(a => a.id === selectedActivity)!} 
                    onGenerate={handleGenerate} 
                    onBack={() => onSelectActivity(null)} 
                    isLoading={isLoading} 
                    activeCurriculumSession={activeCurriculumSession}
                />
            ) : (
                <nav className="flex-1 overflow-y-auto px-2 py-4 space-y-1 custom-scrollbar">
                    {categorizedActivities.map((category) => {
                        const isOpen = openCategoryId === category.id;
                        return (
                            <div key={category.id}>
                                <button onClick={() => isExpanded && setOpenCategoryId(isOpen ? null : category.id)} className={`w-full flex items-center gap-2 px-3 py-2 rounded-xl transition-all ${isOpen && isExpanded ? 'bg-zinc-800 text-white' : 'hover:bg-zinc-100 text-zinc-600 dark:text-zinc-400'}`}>
                                    <i className={`${category.icon} w-5`}></i>
                                    {isExpanded && <span className="flex-1 text-left text-xs font-black uppercase truncate">{category.title}</span>}
                                </button>
                                {isExpanded && isOpen && (
                                    <div className="pl-6 mt-1 space-y-1">
                                        {category.items.map(activity => (
                                            <button key={activity.id} onClick={() => onSelectActivity(activity.id)} className={`w-full text-left px-3 py-1.5 rounded-lg text-[10px] font-bold transition-all ${selectedActivity === activity.id ? 'bg-indigo-50 text-indigo-700' : 'text-zinc-500 hover:text-zinc-900 hover:bg-zinc-50'}`}>
                                                {activity.title}
                                            </button>
                                        ))}
                                    </div>
                                )}
                            </div>
                        );
                    })}
                </nav>
            )}
        </div>
    </aside>
  );
};

export default Sidebar;

import React, { useState, useEffect, useMemo } from 'react';
import { refinePromptWithAI, generateCreativeStudioActivity, analyzeReferenceFiles } from '../../services/generators/creativeStudio';
import { PEDAGOGICAL_LIBRARY, ActivityLibraryItem } from '../../services/generators/promptLibrary';
import { MultimodalFile } from '../../services/geminiClient';
import { EditorPane } from './EditorPane';
import { LibraryPane } from './LibraryPane';
import { ControlPane } from './ControlPane';
import { SmartTooltip } from './components/SmartTooltip';
import { SnippetManagerModal } from './components/SnippetManagerModal';
import { AISnippet, PROFESSIONAL_SNIPPETS } from '../../services/generators/snippetLibrary';
import { ActivityPublisher } from './components/ActivityPublisher';

interface CreativeStudioProps {
    onResult: (data: any) => void;
    onCancel: () => void;
}

const THINKING_MESSAGES = [
    "Gemini 3.0 Pro Motoru Hazırlanıyor...",
    "Bilişsel kısıtlamalar yükleniyor...",
    "Görsel çeldiriciler optimize ediliyor...",
    "Tipografik düzen ayarlanıyor...",
    "Pedagojik metodoloji sentezleniyor...",
    "Nöro-mimari düzen tasarlanıyor...",
    "Klinik analizler tamamlanıyor..."
];

export const CreativeStudio: React.FC<CreativeStudioProps> = ({ onResult, onCancel }) => {
    // Basic States
    const [prompt, setPrompt] = useState("");
    const [difficulty, setDifficulty] = useState("Orta");
    const [itemCount, setItemCount] = useState(8);

    // --- PROFESSIONAL STATES ---
    const [distractionLevel, setDistractionLevel] = useState("medium"); 
    const [fontSizePreference, setFontSizePreference] = useState("medium"); 

    const [isProcessing, setIsProcessing] = useState(false);
    const [isAnalyzingFile, setIsAnalyzingFile] = useState(false);
    const [status, setStatus] = useState("");
    const [statusIndex, setStatusIndex] = useState(0);
    const [activeTab, setActiveTab] = useState<'editor' | 'library'>('editor');

    // Custom Data States
    const [localLibrary, setLocalLibrary] = useState<ActivityLibraryItem[]>([]);
    const [customSnippets, setCustomSnippets] = useState<AISnippet[]>([]);
    const [showSnippetModal, setShowSnippetModal] = useState(false);
    const [lastResult, setLastResult] = useState<any>(null);
    const [showPublishModal, setShowPublishModal] = useState(false);

    const [hoveredItem, setHoveredItem] = useState<ActivityLibraryItem | null>(null);
    const [mousePos, setMousePos] = useState({ x: 0, y: 0 });
    const [attachedFiles, setAttachedFiles] = useState<MultimodalFile[]>([]);

    useEffect(() => {
        const savedLib = localStorage.getItem('custom_pedagogical_lib');
        setLocalLibrary([...PEDAGOGICAL_LIBRARY, ...(savedLib ? JSON.parse(savedLib) : [])]);

        const savedSnippets = localStorage.getItem('custom_ai_snippets_v2');
        if (savedSnippets) setCustomSnippets(JSON.parse(savedSnippets));
    }, []);

    useEffect(() => {
        let interval: any;
        if (isProcessing) {
            interval = setInterval(() => setStatusIndex(prev => (prev + 1) % THINKING_MESSAGES.length), 3500);
        }
        return () => clearInterval(interval);
    }, [isProcessing]);

    const handleFilesSelect = async (files: FileList) => {
        setIsAnalyzingFile(true);
        setStatus("Mimari analiz başlıyor...");
        try {
            const reader = (file: File): Promise<MultimodalFile> => new Promise((res, rej) => {
                const r = new FileReader();
                r.onload = () => res({ data: r.result as string, mimeType: file.type });
                r.onerror = rej;
                r.readAsDataURL(file);
            });
            const newFiles = await Promise.all(Array.from(files).map(reader));
            const combined = [...attachedFiles, ...newFiles];
            setAttachedFiles(combined);
            const analysisResult = await analyzeReferenceFiles(combined, prompt);
            setPrompt(prev => prev.trim() ? `${prev}\n\n---\n\n${analysisResult}` : analysisResult);
            setStatus("Analiz başarılı.");
        } catch (e) {
            setStatus("Hata oluştu.");
        } finally {
            setIsAnalyzingFile(false);
        }
    };

    const handleRefine = async (mode: 'expand' | 'clinical') => {
        setIsProcessing(true);
        try {
            const refined = await refinePromptWithAI(prompt, mode);
            setPrompt(refined);
        } finally { setIsProcessing(false); }
    };

    const handleGenerate = async () => {
        if (!prompt.trim() && attachedFiles.length === 0) return;
        setIsProcessing(true);
        try {
            const result = await generateCreativeStudioActivity(prompt, { 
                difficulty, 
                itemCount,
                distractionLevel,
                fontSizePreference
            }, attachedFiles);
            setLastResult(result);
            onResult(Array.isArray(result) ? result : [result]);
        } catch (e) {
            setStatus("Üretim durduruldu.");
        } finally {
            setIsProcessing(false);
        }
    };

    const activeSnippets = useMemo(() => {
        return [...PROFESSIONAL_SNIPPETS, ...customSnippets].slice(0, 8);
    }, [customSnippets]);

    return (
        <div className="max-w-7xl mx-auto w-full font-['Lexend'] relative">
            <SmartTooltip item={hoveredItem} pos={mousePos} />

            {showSnippetModal && (
                <SnippetManagerModal 
                    onClose={() => setShowSnippetModal(false)}
                    customSnippets={customSnippets}
                    onSaveCustom={(s) => {
                        const updated = [...customSnippets, s];
                        setCustomSnippets(updated);
                        localStorage.setItem('custom_ai_snippets_v2', JSON.stringify(updated));
                    }}
                    onDeleteCustom={(id) => {
                        const updated = customSnippets.filter(s => s.id !== id);
                        setCustomSnippets(updated);
                        localStorage.setItem('custom_ai_snippets_v2', JSON.stringify(updated));
                    }}
                    onSelect={(s) => {
                        setPrompt(prev => prev + "\n\n" + s.value);
                        setShowSnippetModal(false);
                    }}
                />
            )}

            {showPublishModal && lastResult && (
                <ActivityPublisher 
                    blueprint={lastResult} 
                    onClose={() => setShowPublishModal(false)} 
                    onSuccess={() => { setShowPublishModal(false); alert("Modül başarıyla sisteme enjekte edildi!"); }}
                />
            )}

            <div className="flex flex-col md:flex-row justify-between items-center mb-8 gap-4 px-4">
                <div>
                    <h2 className="text-4xl font-black tracking-tighter text-white flex items-center gap-3">
                        <i className="fa-solid fa-wand-magic-sparkles text-indigo-500"></i> AI Creative Studio
                    </h2>
                    <p className="text-zinc-500 text-sm mt-1 uppercase tracking-widest font-bold opacity-60">Professional Clinical Content Designer</p>
                </div>
                <div className="flex items-center gap-3">
                    {lastResult && (
                        <button 
                            onClick={() => setShowPublishModal(true)}
                            className="px-6 py-2.5 bg-emerald-600 hover:bg-emerald-500 text-white rounded-xl text-xs font-black transition-all flex items-center gap-2 shadow-lg"
                        >
                            <i className="fa-solid fa-cloud-arrow-up"></i> MENÜYE EKLE
                        </button>
                    )}
                    <div className="flex bg-zinc-900 border border-white/10 p-1.5 rounded-2xl shadow-inner">
                        <button onClick={() => setActiveTab('editor')} className={`px-8 py-2.5 rounded-xl text-xs font-black transition-all ${activeTab === 'editor' ? 'bg-white text-black shadow-xl' : 'text-zinc-500 hover:text-zinc-300'}`}>TASARIMCI</button>
                        <button onClick={() => setActiveTab('library')} className={`px-8 py-2.5 rounded-xl text-xs font-black transition-all ${activeTab === 'library' ? 'bg-white text-black shadow-xl' : 'text-zinc-500 hover:text-zinc-300'}`}>KÜTÜPHANE</button>
                    </div>
                </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-start px-4 pb-20">
                <div className="lg:col-span-8 flex flex-col gap-6 h-[750px]">
                    {activeTab === 'editor' ? (
                        <EditorPane 
                            prompt={prompt} setPrompt={setPrompt} attachedFiles={attachedFiles}
                            onFilesSelect={handleFilesSelect} onRemoveFile={(idx) => setAttachedFiles(f => f.filter((_, i) => i !== idx))}
                            onRefine={handleRefine} snippets={activeSnippets} isAnalyzing={isAnalyzingFile}
                            onAddSnippet={() => setShowSnippetModal(true)}
                        />
                    ) : (
                        <LibraryPane 
                            items={localLibrary} onAddCustom={() => {}} 
                            onSelect={(item) => { setPrompt(item.basePrompt); setActiveTab('editor'); }}
                            onHover={(item, pos) => { setHoveredItem(item); setMousePos(pos); }}
                        />
                    )}
                </div>

                <div className="lg:col-span-4">
                    <ControlPane 
                        difficulty={difficulty} setDifficulty={setDifficulty}
                        itemCount={itemCount} setItemCount={setItemCount}
                        distractionLevel={distractionLevel} setDistractionLevel={setDistractionLevel}
                        fontSizePreference={fontSizePreference} setFontSizePreference={setFontSizePreference}
                        onGenerate={handleGenerate} onCancel={onCancel}
                        isProcessing={isProcessing} isAnalyzing={isAnalyzingFile}
                        status={status} statusMessage={THINKING_MESSAGES[statusIndex]}
                    />
                </div>
            </div>
        </div>
    );
};

import { Type } from "@google/genai";
import { generateCreativeMultimodal, generateWithSchema, MultimodalFile } from '../geminiClient';
import { PEDAGOGICAL_BASE, CLINICAL_DIAGNOSTIC_GUIDE } from './prompts';

/**
 * generateCreativeStudioActivity: 
 * JSON Repair hatasını önlemek için Type.INTEGER kullanımı ve viewBox kısıtlaması.
 */
export const generateCreativeStudioActivity = async (enrichedPrompt: string, options: any, files?: MultimodalFile[]) => {

    const clinicalDirectives = `
    [KLİNİK PARAMETRELER - KRİTİK]
    1. ZORLUK SEVİYESİ: ${options.difficulty}. Basitlik ve aşama sayısını buna göre ayarla.
    2. ÇELDİRİCİ YOĞUNLUĞU: ${options.distractionLevel}. 'high' ise benzer harf/şekil (b-d, m-n) kullan.
    3. TİPOGRAFİK ÖLÇEK: ${options.fontSizePreference}. 'large' ise metin boyutlarını artır.

    KRİTİK GÖRSEL KURALI: 
    - 'viewBox' her zaman "0 0 100 100" olmalıdır. 
    - ASLA büyük rakamlar (1000000...) kullanma.
    `;

    const prompt = `
    ${PEDAGOGICAL_BASE}
    ${CLINICAL_DIAGNOSTIC_GUIDE}
    ${clinicalDirectives}
    GÖREV: PROFESYONEL EĞİTİM MATERYALİ SENTEZİ
    TALİMAT: ${enrichedPrompt}

    PARAMETRELER:
    - Hedef Öğe Sayısı: ${options.itemCount}
    `;

    const schema = {
        type: Type.OBJECT,
        properties: {
            title: { type: Type.STRING },
            instruction: { type: Type.STRING },
            pedagogicalNote: { type: Type.STRING },
            layoutArchitecture: {
                type: Type.OBJECT,
                properties: {
                    blocks: {
                        type: Type.ARRAY,
                        items: {
                            type: Type.OBJECT,
                            properties: {
                                type: { type: Type.STRING, enum: ['header', 'text', 'grid', 'table', 'svg_shape', 'dual_column', 'image'] },
                                content: { 
                                    type: Type.OBJECT,
                                    properties: {
                                        text: { type: Type.STRING },
                                        cols: { type: Type.INTEGER },
                                        rows: { type: Type.INTEGER },
                                        cells: { type: Type.ARRAY, items: { type: Type.STRING } },
                                        headers: { type: Type.ARRAY, items: { type: Type.STRING } },
                                        data: { type: Type.ARRAY, items: { type: Type.ARRAY, items: { type: Type.STRING } } },
                                        left: { type: Type.ARRAY, items: { type: Type.STRING } },
                                        right: { type: Type.ARRAY, items: { type: Type.STRING } },
                                        prompt: { type: Type.STRING },
                                        viewBox: { type: Type.STRING },
                                        paths: { type: Type.ARRAY, items: { type: Type.STRING } }
                                    }
                                },
                                style: {
                                    type: Type.OBJECT,
                                    properties: {
                                        fontSize: { type: Type.INTEGER },
                                        fontWeight: { type: Type.STRING },
                                        textAlign: { type: Type.STRING }
                                    }
                                },
                                weight: { type: Type.INTEGER }
                            },
                            required: ['type', 'content']
                        }
                    }
                },
                required: ['blocks']
            }
        },
        required: ['title', 'instruction', 'layoutArchitecture']
    };

    return await generateCreativeMultimodal({ prompt, schema, files });
};

/* Fix: Implemented missing prompt refinement utility */
export const refinePromptWithAI = async (prompt: string, mode: 'expand' | 'clinical'): Promise<string> => {
    const instruction = mode === 'expand' 
        ? "Bu promptu pedagojik derinlik katarak, disleksi dostu materyal üretim kurallarıyla zenginleştir."
        : "Bu prompta klinik tanı kriterleri ekle (reversal errors, phonological gaps vb.).";

    const aiPrompt = `[GÖREV: PROMPT MİMARI]\nHAM PROMPT: "${prompt}"\nTALİMAT: ${instruction}\nSadece zenginleştirilmiş metni döndür.`;

    const schema = { 
        type: Type.OBJECT, 
        properties: { refined: { type: Type.STRING } }, 
        required: ['refined'] 
    };
    const result = await generateWithSchema(aiPrompt, schema, 'gemini-3-flash-preview');
    return result.refined;
};

/* Fix: Implemented missing file analysis utility */
export const analyzeReferenceFiles = async (files: MultimodalFile[], currentPrompt: string): Promise<string> => {
    const prompt = `
    [GÖREV: PEDAGOJİK MİMARİ ANALİST]
    Ekteki dosyaları teknik olarak analiz et. 
    KULLANICI TERCİHİ: "${currentPrompt}"

    GÖREVİN: Bu dosyaları referans alarak, Bursa Disleksi AI motorunun BİREBİR AYNI KALİTEDE VE YAPIDA bir çıktı üretmesi için gereken DETAYLI TEKNİK PROMPTU OLUŞTUR.
    İçerisinde [MİMARİ], [İÇERİK PLANI] başlıkları olmalı.
    `;
    const schema = { 
        type: Type.OBJECT, 
        properties: { analysis: { type: Type.STRING } }, 
        required: ['analysis'] 
    };
    const result = await generateCreativeMultimodal({ prompt, schema, files, useFlash: true });
    return result.analysis;
};

