                                                    className={`w-full text-left p-2.5 rounded-xl text-[11px] font-bold transition-all ${selectedActivity === activity.id ? 'bg-indigo-50 text-indigo-700' : 'text-zinc-500 hover:text-zinc-900 hover:bg-zinc-50 dark:hover:bg-zinc-800'}`}
                                                >
                                                    {activity.title}
                                                </button>
                                            ))}
                                        </div>
                                    )}
                                </div>
                            );
                        })}
                    </div>
                </nav>
            )}
        </div>
    </aside>
  );
};

