                    required: ['text', 'answer', 'operationHint']
                }
            }
        },
        required: ['problems']
    };

    // Fix: Removed the third argument 'gemini-3-flash-preview' as generateWithSchema only expects two arguments
    return await generateWithSchema(prompt, schema);
};

