                        {/* Footer Info */}
                        <div className="mt-8 p-4 border border-dashed border-zinc-300 rounded-xl text-xs text-zinc-500 text-center">
                            <p>Değerlendirmeyi Yapan: <strong>{result.respondentRole === 'parent' ? 'Ebeveyn' : 'Öğretmen'}</strong></p>
