const DropdownItem: React.FC<{ icon: string, label: string, onClick: () => void, badge?: number }> = ({ icon, label, onClick, badge }) => (
    <button onClick={onClick} className="w-full flex items-center justify-between px-4 py-3 hover:bg-zinc-50 dark:hover:bg-zinc-800 rounded-xl transition-colors group">
        <div className="flex items-center gap-3">
            <i className={`fa-solid ${icon} w-4 text-center text-zinc-400 group-hover:text-indigo-500 transition-colors`}></i>
            <span className="text-xs font-bold text-zinc-700 dark:text-zinc-300">{label}</span>
        </div>
        {badge !== undefined && badge > 0 && <span className="bg-indigo-600 text-white text-[9px] font-black px-1.5 py-0.5 rounded-full">{badge}</span>}
    </button>
);

const AppContent: React.FC = () => {
    const { user, logout } = useAuth();
    const { activeStudent, setActiveStudent, students } = useStudent();
    const [currentView, setCurrentView] = useState<ExtendedView>('generator');
    const [viewHistory, setViewHistory] = useState<ExtendedView[]>([]); 
    const [selectedActivity, setSelectedActivity] = useState<ActivityType | null>(null);
    const [worksheetData, setWorksheetData] = useState<WorksheetData>(null);
    const [isLoading, setIsLoading] = useState<boolean>(false);
    const [error, setError] = useState<string | null>(null);
    const [activeCurriculumSession, setActiveCurriculumSession] = useState<ActiveCurriculumSession | null>(null);
    const [loadedCurriculum, setLoadedCurriculum] = useState<Curriculum | null>(null);
    const [isSidebarOpen, setIsSidebarOpen] = useState(false);
    const [isSidebarExpanded, setIsSidebarExpanded] = useState(true);
    const [zenMode, setZenMode] = useState(false);
    const [openModal, setOpenModal] = useState<ModalType | null>(null);
    const [isFeedbackOpen, setIsFeedbackOpen] = useState(false);
    const [isAuthModalOpen, setIsAuthModalOpen] = useState(false);
    const [unreadCount, setUnreadCount] = useState(0);
    const [isTourOpen, setIsTourOpen] = useState(false);
    const [studentProfile, setStudentProfile] = useState<StudentProfile | null>(null);
    const [isStudentModalOpen, setIsStudentModalOpen] = useState(false);
    const [selectedSavedReport, setSelectedSavedReport] = useState<SavedAssessment | null>(null);
    const [workbookItems, setWorkbookItems] = useState<CollectionItem[]>([]);
    const [workbookSettings, setWorkbookSettings] = useState<WorkbookSettings>({
        title: 'Çalışma Kitapçığı', studentName: '', schoolName: '', year: new Date().getFullYear().toString(),
        teacherNote: '', theme: 'modern', accentColor: '#4f46e5', coverStyle: 'centered',
        showTOC: true, showPageNumbers: true, showWatermark: false, watermarkOpacity: 0.05, showBackCover: true
    });

    // Screening to Plan Bridge
    const [screeningPlanData, setScreeningPlanData] = useState<{name: string, age: number, weaknesses: string[], diagnosisContext?: string} | null>(null);

    const [theme, setTheme] = useState<AppTheme>(() => {
        try { const storedTheme = localStorage.getItem('app-theme'); return (storedTheme as AppTheme) || 'anthracite'; } catch (e) { return 'anthracite'; }
    });
    const [uiSettings, setUiSettings] = useState<UiSettings>(() => {
        try { const stored = localStorage.getItem('app-ui-settings'); return stored ? { ...initialUiSettings, ...JSON.parse(stored) } : initialUiSettings; } catch (e) { return initialUiSettings; }
    });
    const [styleSettings, setStyleSettings] = useState<StyleSettings>(initialStyleSettings);
    const [historyItems, setHistoryItems] = useState<HistoryItem[]>(() => {
        try { const stored = localStorage.getItem('user_history'); return stored ? JSON.parse(stored) : []; } catch { return []; }
    });

    const navigateTo = (view: ExtendedView) => { if (currentView === view) return; setViewHistory(prev => [...prev, currentView]); setCurrentView(view); };
    const handleGoBack = () => {
        if (currentView === 'generator' && activeCurriculumSession) { setActiveCurriculumSession(null); navigateTo('curriculum'); return; }
        if (viewHistory.length > 0) { const newHistory = [...viewHistory]; const prevView = newHistory.pop(); setViewHistory(newHistory); if (prevView) setCurrentView(prevView); } else { setCurrentView('generator'); }
    };

    // --- NAVIGATION HELPERS (Resets state before switching view) ---
    const handleOpenStudio = (viewName: ExtendedView) => {
        setSelectedActivity(null); 
        setWorksheetData(null);
        setActiveCurriculumSession(null);
        navigateTo(viewName);
    };

    const handleGeneratePlanFromScreening = (studentName: string, age: number, weaknesses: string[], diagnosisContext?: string) => {
        setScreeningPlanData({ name: studentName, age, weaknesses, diagnosisContext });
        handleOpenStudio('curriculum');
    };

    useEffect(() => { localStorage.setItem('user_history', JSON.stringify(historyItems)); }, [historyItems]);
    const addToHistory = (activityType: ActivityType, data: SingleWorksheetData[]) => {
        const activity = ACTIVITIES.find(a => a.id === activityType);
        const category = ACTIVITY_CATEGORIES.find(c => c.activities.includes(activityType));
        if (!activity || !category) return;
        const newItem: HistoryItem = { id: Date.now().toString() + Math.random(), userId: user?.id || 'guest', activityType, data, timestamp: new Date().toISOString(), title: activity.title, category: { id: category.id, title: category.title } };
        setHistoryItems(prev => [newItem, ...prev].slice(0, 100));
    };
    const clearHistory = () => { setHistoryItems([]); };
    const deleteHistoryItem = (id: string) => { setHistoryItems(prev => prev.filter(i => i.id !== id)); };
    const handleRestoreFromHistory = (item: HistoryItem) => { loadSavedWorksheet({ id: item.id, userId: item.userId, name: item.title, activityType: item.activityType, worksheetData: item.data, createdAt: item.timestamp, icon: ACTIVITIES.find(a => a.id === item.activityType)?.icon || 'fa-file', category: item.category }); setOpenModal(null); };
    const handleSaveHistoryItem = (item: HistoryItem) => { if (!user) { setIsAuthModalOpen(true); return; } addSavedWorksheet(`${item.title} (Geçmiş)`, item.activityType, item.data); };
    const addSavedWorksheet = async (name: string, activityType: ActivityType, data: SingleWorksheetData[]) => {
        if (!user) { setIsAuthModalOpen(true); return; }
        const activity = ACTIVITIES.find(a => a.id === activityType);
        const category = ACTIVITY_CATEGORIES.find(c => c.activities.includes(activityType));
        if (!activity || !category) return;
        try { await worksheetService.saveWorksheet(user.id, name, activityType, data, activity.icon, { id: category.id, title: category.title }, styleSettings, studentProfile || undefined, studentProfile?.studentId); alert(`Etkinlik "${name}" adıyla arşivinize kaydedildi.`); } catch (e: any) { alert(`Kaydedilirken bir hata oluştu: ${e.message}.`); }
    };

    const loadSavedWorksheet = (item: any) => {
        if (item.report || item.activityType === ActivityType.ASSESSMENT_REPORT) { setSelectedSavedReport(item as SavedAssessment); return; }
        if (item.schedule && item.durationDays) { setLoadedCurriculum(item as Curriculum); navigateTo('curriculum'); return; }
        if (item.activityType === ActivityType.WORKBOOK || item.workbookItems) { if (item.workbookItems && item.workbookSettings) { setWorkbookItems(item.workbookItems); setWorkbookSettings(item.workbookSettings); navigateTo('workbook'); } return; }
        setSelectedActivity(item.activityType); setWorksheetData(item.worksheetData); if (item.styleSettings) setStyleSettings(item.styleSettings);
        if (item.studentProfile) { setStudentProfile(item.studentProfile); if (item.studentId) { const s = students.find(x => x.id === item.studentId); if (s) setActiveStudent(s); } } else { setStudentProfile(null); setActiveStudent(null); }
        navigateTo('generator'); setIsSidebarExpanded(true); 
    };

    const handleSelectActivity = (activityType: ActivityType | null) => { if (currentView !== 'generator') navigateTo('generator'); setActiveCurriculumSession(null); setSelectedActivity(activityType); setWorksheetData(null); setError(null); setCurrentView('generator'); if (isSidebarOpen) setIsSidebarOpen(false); if (activityType) setIsSidebarExpanded(true); };
    const handleStartCurriculumActivity = (planId: string, day: number, activityId: string, activityType: string, studentName: string, title: string, difficulty: 'Easy' | 'Medium' | 'Hard', goal: string, studentId?: string) => { setActiveCurriculumSession({ planId, day, activityId, studentName, activityTitle: title, studentId, difficulty, goal }); if (studentId) { const s = students.find(x => x.id === studentId); if (s) setActiveStudent(s); } else { setStudentProfile({ name: studentName, school: '', grade: '', date: new Date().toLocaleDateString('tr-TR') }); } setSelectedActivity(activityType as ActivityType); setWorksheetData(null); navigateTo('generator'); setIsSidebarExpanded(true); };
    const handleCompleteCurriculumActivity = async () => {
        if (!activeCurriculumSession || !user) return; setIsLoading(true);
        try { if (worksheetData) await addSavedWorksheet(`${activeCurriculumSession.studentName} - ${activeCurriculumSession.activityTitle}`, selectedActivity!, worksheetData); await curriculumService.updateActivityStatus(activeCurriculumSession.planId, activeCurriculumSession.day, activeCurriculumSession.activityId, 'completed'); setActiveCurriculumSession(null); navigateTo('curriculum'); alert("Harika! Aktivite tamamlandı ve plana işlendi."); } catch (e) { alert("Bir hata oluştu."); } finally { setIsLoading(false); }
    };

    const handleAddToWorkbookGeneral = (activityType: ActivityType, data: any) => {
        if (activityType && data) {
            const dataArray = Array.isArray(data) ? data : [data];
            const newItems: CollectionItem[] = dataArray.map((sheet: any) => ({ id: crypto.randomUUID(), activityType: activityType, data: sheet, settings: { ...styleSettings }, title: sheet.title || ACTIVITIES.find(a => a.id === activityType)?.title || 'Etkinlik' }));
            setWorkbookItems(prev => [...prev, ...newItems]);
            const btn = document.getElementById('add-to-wb-btn');
            if(btn) { btn.classList.add('scale-125', 'bg-green-500', 'text-white'); setTimeout(() => btn.classList.remove('scale-125', 'bg-green-500', 'text-white'), 300); }
        }
    };
    const handleAddToWorkbook = () => { if (selectedActivity && worksheetData) handleAddToWorkbookGeneral(selectedActivity, worksheetData); };
    const handleAddDirectToWorkbook = (item: any) => {
        const newItems: CollectionItem[] = [{ id: crypto.randomUUID(), activityType: item.activityType, data: item.data, settings: { ...styleSettings, ...item.settings }, title: item.title }];
        setWorkbookItems(prev => [...prev, ...newItems]);
    };

    const handleOCRResult = (result: any) => { setSelectedActivity(ActivityType.OCR_CONTENT); setWorksheetData(result); navigateTo('generator'); setIsSidebarExpanded(true); };
    const handleAutoGenerateWorkbook = async (report: AssessmentReport) => {
        setIsLoading(true); navigateTo('workbook'); const newItems: CollectionItem[] = [];
        const defaultOptions: GeneratorOptions = { mode: 'fast', difficulty: 'Orta', worksheetCount: 1, itemCount: 10, gridSize: 10, operationType: 'mixed', numberRange: '1-20' };
        try {
            const reportItem: CollectionItem = { id: crypto.randomUUID(), activityType: ActivityType.ASSESSMENT_REPORT, data: { id: 'temp-report', userId: user?.id || 'guest', studentName: studentProfile?.name || 'Öğrenci', gender: 'Erkek', age: 7, grade: studentProfile?.grade || '1. Sınıf', createdAt: new Date().toISOString(), report: report } as SavedAssessment, settings: { ...styleSettings, showStudentInfo: false, showFooter: false }, title: `Rapor: ${studentProfile?.name || 'Öğrenci'}` };
            newItems.push(reportItem);
            for (const roadItem of report.roadmap) {
                const activityId = roadItem.activityId as ActivityType;
                const pascalName = activityId.toLowerCase().split('_').map(word => word.charAt(0).toUpperCase() + word.slice(1)).join('');
                const generatorName = `generateOffline${pascalName}`;
                const generator = (offlineGenerators as any)[generatorName];
                if (generator) {
                    try { const generatedData = await generator(defaultOptions); generatedData.forEach((sheet: any) => { newItems.push({ id: crypto.randomUUID(), activityType: activityId, data: sheet, settings: { ...styleSettings }, title: ACTIVITIES.find(a => a.id === activityId)?.title || activityId }); }); } catch (genErr) { console.error(`Failed to auto-generate ${activityId}`, genErr); }
                }
            }
            setWorkbookItems(newItems); setWorkbookSettings(prev => ({ ...prev, title: `Kişisel Gelişim Planı`, studentName: studentProfile?.name || '', teacherNote: "Bu kitapçık, yapılan değerlendirme sonucunda belirlenen ihtiyaçlara yönelik olarak yapay zeka tarafından otomatik oluşturulmuştur." }));
        } catch (e) { alert("Otomatik kitapçık oluşturulurken bir hata meydana geldi."); } finally { setIsLoading(false); }
    };

    return (
        <div className="flex flex-col h-screen bg-transparent font-sans transition-colors duration-300">
            <header className={`relative bg-white/90 dark:bg-zinc-900/90 backdrop-blur-md border-b border-zinc-200 dark:border-zinc-800 shadow-sm z-50 transition-all duration-500 ${zenMode ? '-mt-24 opacity-0 pointer-events-none' : 'mt-0 opacity-100'}`}>
                <div className="w-full px-6 py-4 flex justify-between items-center gap-6">

                    <div className="flex items-center gap-4">
                        <button onClick={() => setIsSidebarOpen(true)} className="md:hidden text-zinc-400 p-2 hover:text-zinc-900 transition-colors"><i className="fa-solid fa-bars-staggered fa-lg"></i></button>
                        <button id="tour-logo" onClick={() => { navigateTo('generator'); setSelectedActivity(null); setWorksheetData(null); setActiveCurriculumSession(null); }} className="flex items-center gap-3">
                            <DyslexiaLogo className="h-10 w-auto" />
                        </button>
                    </div>

                    <div className="flex-1 max-w-xl hidden md:block">
                        <GlobalSearch onSelectActivity={handleSelectActivity} />
                    </div>

                    <div className="flex items-center gap-2">
                        <button 
                            onClick={() => handleOpenStudio('assessment')} 
                            className="hidden sm:flex items-center gap-2 px-6 py-2.5 bg-indigo-600 hover:bg-indigo-700 text-white rounded-2xl text-xs font-black shadow-lg shadow-indigo-200 dark:shadow-none transition-all active:scale-95"
                        >
                            <i className="fa-solid fa-user-doctor"></i> DEĞERLENDİRME
                        </button>

                        <div className="h-8 w-px bg-zinc-200 dark:bg-zinc-800 mx-2"></div>

                        <div className="flex items-center gap-1">
                            <button onClick={() => navigateTo('workbook')} className="relative p-2.5 text-zinc-400 hover:text-emerald-500 transition-all rounded-xl hover:bg-emerald-50" title="Kitapçık">
                                <i className="fa-solid fa-book-medical fa-lg"></i>
                                {workbookItems.length > 0 && <span className="absolute top-0.5 right-0.5 bg-emerald-500 text-white text-[9px] font-black w-4 h-4 flex items-center justify-center rounded-full border-2 border-white">{workbookItems.length}</span>}
                            </button>
                            <button onClick={() => navigateTo('messages')} className="relative p-2.5 text-zinc-400 hover:text-indigo-500 transition-all rounded-xl hover:bg-indigo-50" title="Mesajlar">
                                <i className="fa-solid fa-comment-dots fa-lg"></i>
                                {unreadCount > 0 && <span className="absolute top-0.5 right-0.5 bg-red-500 text-white text-[9px] font-black w-4 h-4 flex items-center justify-center rounded-full border-2 border-white">{unreadCount}</span>}
                            </button>
                        </div>

                        <HeaderDropdown label="Kitaplığım" icon="fa-bookmark" colorClass="text-emerald-600 dark:text-emerald-400">
                            <DropdownItem icon="fa-heart" label="Favoriler" onClick={() => navigateTo('favorites')} />
                            <DropdownItem icon="fa-box-archive" label="Arşiv" onClick={() => navigateTo('savedList')} />
                            <DropdownItem icon="fa-share-nodes" label="Paylaşılanlar" onClick={() => navigateTo('shared')} />
                            <DropdownItem icon="fa-clock-rotate-left" label="İşlem Geçmişi" onClick={() => setOpenModal('history')} />
                        </HeaderDropdown>

                        <HeaderDropdown label="Destek" icon="fa-circle-info">
                            <DropdownItem icon="fa-circle-play" label="Tur Başlat" onClick={() => setIsTourOpen(true)} />
                            <DropdownItem icon="fa-headset" label="Yardım Masası" onClick={() => setIsFeedbackOpen(true)} />
                            <DropdownItem icon="fa-circle-question" label="Hakkımızda" onClick={() => setOpenModal('about')} />
                            <DropdownItem icon="fa-laptop-code" label="Geliştirici" onClick={() => setOpenModal('developer')} />
                        </HeaderDropdown>

                        <div className="h-8 w-px bg-zinc-200 dark:bg-zinc-800 mx-2"></div>

                        {user ? (
                            <HeaderDropdown label={user.name.split(' ')[0]} icon="fa-user-circle" colorClass="text-zinc-900 dark:text-white">
                                <DropdownItem icon="fa-user-gear" label="Profil Ayarları" onClick={() => navigateTo('profile')} />
                                <DropdownItem icon="fa-sliders" label="Görünüm Ayarları" onClick={() => setOpenModal('settings')} />
                                {user.role === 'admin' && <div className="h-px bg-zinc-100 dark:bg-zinc-800 my-1"></div>}
                                {user.role === 'admin' && <DropdownItem icon="fa-shield-halved" label="Admin Paneli" onClick={() => navigateTo('admin')} />}
                                <div className="h-px bg-zinc-100 dark:bg-zinc-800 my-1"></div>
                                <DropdownItem icon="fa-arrow-right-from-bracket" label="Çıkış Yap" onClick={logout} />
                            </HeaderDropdown>
                        ) : (
                            <button onClick={() => setIsAuthModalOpen(true)} className="px-6 py-2.5 bg-zinc-900 text-white dark:bg-white dark:text-black rounded-2xl text-xs font-black shadow-lg transition-all active:scale-95">GİRİŞ YAP</button>
                        )}
                    </div>
                </div>
            </header>

            <div className="flex flex-1 overflow-hidden">
                {isSidebarOpen && <div className="fixed inset-0 bg-black/50 z-40 md:hidden" onClick={() => setIsSidebarOpen(false)}></div>}
                <div onMouseEnter={() => setIsSidebarExpanded(true)} className={`transition-all duration-500 ease-in-out h-full ${zenMode ? '-ml-80 w-0 opacity-0 overflow-hidden' : ''}`}>
                    <Sidebar
                        isSidebarOpen={isSidebarOpen} closeSidebar={() => setIsSidebarOpen(false)} selectedActivity={selectedActivity}
                        onSelectActivity={handleSelectActivity} setWorksheetData={setWorksheetData} setIsLoading={setIsLoading}
                        setError={setError} isLoading={isLoading} onAddToHistory={addToHistory}
                        onOpenOCR={() => handleOpenStudio('ocr')} 
                        onOpenCurriculum={() => handleOpenStudio('curriculum')}
                        onOpenReadingStudio={() => handleOpenStudio('reading-studio')} 
                        onOpenMathStudio={() => handleOpenStudio('math-studio')}
                        onOpenScreening={() => handleOpenStudio('screening')}
                        activeCurriculumSession={activeCurriculumSession} isExpanded={isSidebarExpanded}
                    />
                </div>
                <div className="flex-1 flex flex-col overflow-hidden" onMouseEnter={() => setIsSidebarExpanded(false)}>
                    <ContentArea
                        currentView={currentView as View} onBackToGenerator={() => { if(currentView !== 'generator') handleGoBack(); else { setSelectedActivity(null); setWorksheetData(null); setActiveCurriculumSession(null); } }}
                        activityType={selectedActivity} worksheetData={worksheetData} isLoading={isLoading} error={error}
                        styleSettings={styleSettings} onStyleChange={setStyleSettings} onSave={addSavedWorksheet}
                        onLoadSaved={loadSavedWorksheet} onFeedback={() => setIsFeedbackOpen(true)} onOpenAuth={() => setIsAuthModalOpen(true)}
                        onSelectActivity={handleSelectActivity} workbookItems={workbookItems} setWorkbookItems={setWorkbookItems}
                        workbookSettings={workbookSettings} setWorkbookSettings={setWorkbookSettings} onAddToWorkbook={handleAddToWorkbook}
                        onAutoGenerateWorkbook={handleAutoGenerateWorkbook} studentProfile={studentProfile} zenMode={zenMode}
                        toggleZenMode={() => setZenMode(!zenMode)} activeCurriculumSession={activeCurriculumSession}
                        onCompleteCurriculumActivity={handleCompleteCurriculumActivity}
                        onAddDirectToWorkbook={handleAddDirectToWorkbook}
                    />
                </div>
            </div>

            {/* SPECIAL RENDER FOR STUDIOS WHEN IN THAT VIEW */}
            {currentView === 'curriculum' && (
                 <div className="absolute inset-0 bg-white dark:bg-zinc-900 z-[60] overflow-hidden">
                    <React.Suspense fallback={<LoadingSpinner />}>
                        <CurriculumView 
                            onBack={handleGoBack} 
                            onSelectActivity={handleSelectActivity as any} 
                            onStartCurriculumActivity={handleStartCurriculumActivity} 
                            initialPlan={loadedCurriculum}
                            preFillData={screeningPlanData}
                        />
                    </React.Suspense>
                </div>
            )}

            {currentView === 'reading-studio' && (
                <div className="absolute inset-0 bg-white dark:bg-zinc-900 z-[60] overflow-hidden">
                    <React.Suspense fallback={<LoadingSpinner />}>
                        <ReadingStudio onBack={handleGoBack} onAddToWorkbook={handleAddToWorkbookGeneral as any} />
                    </React.Suspense>
                </div>
            )}

            {currentView === 'math-studio' && (
                <div className="absolute inset-0 bg-white dark:bg-zinc-900 z-[60] overflow-hidden">
                    <React.Suspense fallback={<LoadingSpinner />}>
                        <MathStudio onBack={handleGoBack} onAddToWorkbook={handleAddToWorkbookGeneral as any} />
                    </React.Suspense>
                </div>
            )}

            {currentView === 'ocr' && (
                <div className="absolute inset-0 bg-white dark:bg-zinc-900 z-[60] overflow-hidden">
                     <React.Suspense fallback={<LoadingSpinner />}>
                        <OCRScanner onBack={handleGoBack} onResult={handleOCRResult} />
                    </React.Suspense>
                </div>
            )}

            {currentView === 'students' && (
                <div className="absolute inset-0 bg-white dark:bg-zinc-900 z-[60] overflow-hidden">
                    <React.Suspense fallback={<LoadingSpinner />}>
                        <StudentDashboard onBack={handleGoBack} onLoadMaterial={loadSavedWorksheet} />
                    </React.Suspense>
                </div>
            )}

            {currentView === 'messages' && (
                <div className="absolute inset-0 bg-white dark:bg-zinc-900 z-[60] overflow-hidden">
                    <React.Suspense fallback={<LoadingSpinner />}>
                        <MessagesView onBack={handleGoBack} />
                    </React.Suspense>
                </div>
            )}

            {/* Admin view is special, keeps its own context */}
            {currentView === 'admin' && (
                 <div className="absolute inset-0 bg-white dark:bg-zinc-900 z-[70] overflow-hidden">
                    <React.Suspense fallback={<LoadingSpinner />}>
                        <AdminDashboard onBack={handleGoBack} />
                    </React.Suspense>
                </div>
            )}

            {/* Assessment and Screening run inside ContentArea via currentView prop, but need special handling in ContentArea */}
            {currentView === 'screening' && (
                 <div className="absolute inset-0 bg-white dark:bg-zinc-900 z-[60] overflow-hidden">
                    <React.Suspense fallback={<LoadingSpinner />}>
                        <ScreeningModule 
                            onBack={handleGoBack} 
                            onSelectActivity={handleSelectActivity} 
                            onAddToWorkbook={handleAddToWorkbookGeneral as any}
                            onGeneratePlan={(n, a, w, c) => handleGeneratePlanFromScreening(n, a, w, c)}
                        />
                    </React.Suspense>
                </div>
            )}

            <TourGuide steps={tourSteps} isOpen={isTourOpen} onClose={() => setIsTourOpen(false)} />
            <FeedbackModal isOpen={isFeedbackOpen} onClose={() => setIsFeedbackOpen(false)} activityType={selectedActivity} activityTitle={selectedActivity ? ACTIVITIES.find(a => a.id === selectedActivity)?.title : undefined} />
            <AuthModal isOpen={isAuthModalOpen} onClose={() => setIsAuthModalOpen(false)} />
            <StudentInfoModal isOpen={isStudentModalOpen} onClose={() => setIsStudentModalOpen(false)} currentProfile={studentProfile} onSave={(p) => setStudentProfile(p)} onClear={() => setStudentProfile(null)} />
            <SettingsModal isOpen={openModal === 'settings'} onClose={() => setOpenModal(null)} uiSettings={uiSettings} onUpdateUiSettings={setUiSettings} theme={theme} onUpdateTheme={setTheme} />
            <AssessmentReportViewer assessment={selectedSavedReport} onClose={() => setSelectedSavedReport(null)} user={user} onSelectActivity={handleSelectActivity} onGeneratePlan={(name, age, weaknesses, context) => handleGeneratePlanFromScreening(name, age, weaknesses, context)} />
            <Modal isOpen={openModal === 'history'} onClose={() => setOpenModal(null)} title="İşlem Geçmişi"><HistoryView historyItems={historyItems} onRestore={handleRestoreFromHistory} onSaveToArchive={handleSaveHistoryItem} onDelete={deleteHistoryItem} onClearAll={clearHistory} onClose={() => setOpenModal(null)} /></Modal>
            <Modal isOpen={openModal === 'about'} onClose={() => setOpenModal(null)} title="Hakkımızda"><div className="text-center space-y-6"><DyslexiaLogo className="h-16 w-auto mx-auto" /><div className="space-y-4 text-zinc-600 dark:text-zinc-300"><p className="leading-relaxed">Bursa Disleksi AI, özel öğrenme güçlüğü yaşayan bireylerin eğitim süreçlerini desteklemek, eğitmen ve ailelere kişiselleştirilmiş, bilimsel temelli materyaller sunmak amacıyla geliştirilmiş yeni nesil bir yapay zeka platformudur.</p></div></div></Modal>
        </div>
    );
};

export const App: React.FC = () => {
    return (
        <AuthProvider>
            <StudentProvider>
                <AppContent />
            </StudentProvider>
        </AuthProvider>
    );
};

import React, { useState, useEffect } from 'react';
import { curriculumService } from '../services/curriculumService';
import { Curriculum, CurriculumDay, CurriculumActivity, Student, ActivityType } from '../types';
import { ACTIVITIES } from '../constants';
import { printService } from '../utils/printService';
import { useAuth } from '../context/AuthContext';
import { useStudent } from '../context/StudentContext';
import { ShareModal } from './ShareModal';

interface CurriculumViewProps {
    onBack: () => void;
    onSelectActivity: (id: string) => void;
    onStartCurriculumActivity: (planId: string, day: number, activityId: string, activityType: string, studentName: string, title: string, difficulty: 'Easy' | 'Medium' | 'Hard', goal: string, studentId?: string) => void;
    initialPlan?: Curriculum | null;
    preFillData?: { name: string; age: number; weaknesses: string[], diagnosisContext?: string } | null;
}

const DayCard: React.FC<{ 
    day: CurriculumDay, 
    isActiveDay: boolean,
    onToggleActivity: (day: number, actId: string) => void, 
    onStartActivity: (actId: string, actType: string, title: string, difficulty: 'Easy' | 'Medium' | 'Hard', goal: string) => void,
    onSaveNote: (day: number, note: string) => void
}> = ({ day, isActiveDay, onToggleActivity, onStartActivity, onSaveNote }) => {
    const isAllCompleted = day.activities.every(a => a.status === 'completed');

    return (
        <div className={`group relative bg-white dark:bg-zinc-800 rounded-3xl border-2 transition-all duration-500 hover:shadow-2xl ${isActiveDay ? 'ring-4 ring-indigo-500/20 border-indigo-500 scale-[1.02] z-10 shadow-xl' : 'border-zinc-100 dark:border-zinc-700'} ${isAllCompleted ? 'opacity-80 grayscale-[0.3]' : ''} break-inside-avoid page-break-inside-avoid print:border-zinc-300 print:shadow-none`}>
            {isActiveDay && (
                <div className="absolute -top-3 left-1/2 -translate-x-1/2 bg-indigo-600 text-white px-4 py-1 rounded-full text-[10px] font-black uppercase tracking-widest shadow-lg animate-bounce z-20">
                    ŞU AN BURADAYIZ
                </div>
            )}

            <div className={`p-5 rounded-t-[1.3rem] flex justify-between items-center ${isActiveDay ? 'bg-indigo-50 dark:bg-indigo-900/20' : 'bg-zinc-50 dark:bg-zinc-900/50'} border-b border-zinc-100 dark:border-zinc-700`}>
                <div>
                    <h4 className="font-black text-xl text-zinc-800 dark:text-white flex items-center gap-2">
                        {day.day}. Gün
                        {isAllCompleted && <i className="fa-solid fa-circle-check text-emerald-500"></i>}
                    </h4>
                    <p className="text-xs font-bold text-indigo-500 dark:text-indigo-400 uppercase tracking-wider mt-1 line-clamp-1">{day.focus}</p>
                </div>
                <div className={`w-10 h-10 rounded-2xl flex items-center justify-center shadow-sm border ${isActiveDay ? 'bg-white dark:bg-zinc-700 border-indigo-200' : 'bg-white dark:bg-zinc-700 border-zinc-100'}`}>
                    <i className={`fa-solid ${isAllCompleted ? 'fa-star text-amber-500' : 'fa-calendar-day text-zinc-400'}`}></i>
                </div>
            </div>

            <div className="p-5 space-y-4">
                {day.activities.map((act) => (
                    <div key={act.id} className={`relative pl-4 border-l-4 transition-all ${act.status === 'completed' ? 'border-emerald-400' : 'border-zinc-200 dark:border-zinc-700 hover:border-indigo-400'}`}>
                        <div className="flex justify-between items-start gap-4">
                            <div className="flex-1 min-w-0">
                                <h5 className={`font-bold text-sm truncate ${act.status === 'completed' ? 'line-through text-zinc-400' : 'text-zinc-800 dark:text-zinc-200'}`}>{act.title}</h5>
                                <div className="flex items-center gap-2 mt-1">
                                    <span className="text-[9px] bg-zinc-100 dark:bg-zinc-700 px-1.5 py-0.5 rounded text-zinc-500 dark:text-zinc-400 font-mono">{act.duration} dk</span>
                                    <span className={`text-[9px] px-1.5 py-0.5 rounded font-black uppercase ${act.difficultyLevel === 'Hard' ? 'text-rose-600 bg-rose-50' : act.difficultyLevel === 'Medium' ? 'text-amber-600 bg-amber-50' : 'text-emerald-600 bg-emerald-50'}`}>
                                        {act.difficultyLevel === 'Hard' ? 'Zor' : act.difficultyLevel === 'Medium' ? 'Orta' : 'Kolay'}
                                    </span>
                                </div>
                                <p className="text-[10px] text-zinc-500 mt-1 italic line-clamp-2 leading-tight">{act.goal}</p>
                            </div>
                            <div className="flex flex-col gap-2 shrink-0">
                                <button 
                                    onClick={() => onToggleActivity(day.day, act.id)}
                                    className={`w-8 h-8 rounded-full border-2 flex items-center justify-center transition-all ${act.status === 'completed' ? 'bg-emerald-500 border-emerald-500 text-white' : 'border-zinc-200 dark:border-zinc-600 hover:border-emerald-500 text-transparent hover:text-emerald-500'}`}
                                >
                                    <i className="fa-solid fa-check text-xs"></i>
                                </button>
                                {act.status !== 'completed' && (
                                    <button 
                                        onClick={() => onStartActivity(act.activityId, act.activityId, act.title, act.difficultyLevel, act.goal)}
                                        className="w-8 h-8 rounded-xl bg-indigo-600 text-white flex items-center justify-center hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-500/20 active:scale-90"
                                        title="Uygulamayı Başlat"
                                    >
                                        <i className="fa-solid fa-wand-magic-sparkles text-[10px]"></i>
                                    </button>
                                )}
                            </div>
                        </div>
                    </div>
                ))}

                <div className="pt-4 mt-2 border-t border-dashed border-zinc-100 dark:border-zinc-700 print:hidden">
                    <label className="text-[9px] font-black text-zinc-400 uppercase tracking-widest mb-1.5 block">Gözlem Notu</label>
                    <textarea 
                        className="w-full p-3 bg-zinc-50 dark:bg-zinc-900 border border-zinc-100 dark:border-zinc-700 rounded-xl text-[11px] resize-none focus:border-indigo-300 outline-none transition-all placeholder:text-zinc-300"
                        placeholder="Öğrencinin bugünkü tepkisi, odak süresi..."
                        rows={2}
                        defaultValue={day.focus === day.focus ? day.focus : ''}
                        onBlur={(e) => onSaveNote(day.day, e.target.value)}
                    ></textarea>
                </div>
            </div>
        </div>
    );
};

export const CurriculumView: React.FC<CurriculumViewProps> = ({ onBack, onSelectActivity, onStartCurriculumActivity, initialPlan, preFillData }) => {
    const { user } = useAuth();
    const { students, setActiveStudent } = useStudent();

    const [step, setStep] = useState(0); 
    const [loading, setLoading] = useState(false);
    const [isSaving, setIsSaving] = useState(false);
    const [curriculum, setCurriculum] = useState<Curriculum | null>(null);
    const [isSaved, setIsSaved] = useState(false);
    const [isShareModalOpen, setIsShareModalOpen] = useState(false);
    const [isPrinting, setIsPrinting] = useState(false);

    const [formData, setFormData] = useState<Partial<Student>>({
        name: '', age: 8, grade: '2. Sınıf', diagnosis: [], interests: [], weaknesses: []
    });
    const [planDuration, setPlanDuration] = useState(7);
    const [diagnosisContext, setDiagnosisContext] = useState<string>('');

    useEffect(() => {
        if (initialPlan) {
            setCurriculum(initialPlan);
            setStep(4);
            setIsSaved(true);
            setFormData({
                id: initialPlan.studentId || '',
                name: initialPlan.studentName,
                grade: initialPlan.grade,
                interests: initialPlan.interests,
                weaknesses: initialPlan.weaknesses
            });
            setPlanDuration(initialPlan.durationDays);
        } else if (preFillData) {
            // TARAMADAN GELEN VERİ
            setFormData({
                name: preFillData.name,
                age: preFillData.age,
                grade: '1. Sınıf', // Varsayılan veya taramadan gelebilir
                weaknesses: preFillData.weaknesses,
                interests: [] // Kullanıcıya tamamlat
            });
            if (preFillData.diagnosisContext) {
                setDiagnosisContext(preFillData.diagnosisContext);
            }
            setStep(1); // Doğrudan detay ekranına git
        }
    }, [initialPlan, preFillData]);

    const handleStudentSelect = (sid: string) => {
        if (sid === 'new') {
            setFormData({ name: '', age: 8, grade: '2. Sınıf', diagnosis: [], interests: [], weaknesses: [] });
            setActiveStudent(null);
        } else {
            const student = students.find(s => s.id === sid);
            if (student) {
                setFormData(student);
                setActiveStudent(student);
            }
        }
    };

    const handleGenerate = async () => {
        if (!formData.name) return;
        setLoading(true);
        try {
            // Context varsa onu da gönderiyoruz
            const studentData = { ...formData };
            if (diagnosisContext) {
                studentData.notes = `KLİNİK TANI BAĞLAMI:\n${diagnosisContext}\n\n${studentData.notes || ''}`;
            }

            const plan = await curriculumService.generatePlan(studentData, planDuration);
            setCurriculum(plan);
            setStep(4);
            setIsSaved(false);
        } catch (e) {
            alert("Plan oluşturulurken bir hata oluştu.");
        } finally {
            setLoading(false);
        }
    };

    const handleSave = async () => {
        if (!user || !curriculum) return;
        setIsSaving(true);
        try {
            const id = await curriculumService.saveCurriculum(user.id, curriculum);
            setCurriculum({ ...curriculum, id });
            setIsSaved(true);
        } catch (e) {
            alert("Kaydetme hatası.");
        } finally {
            setIsSaving(false);
        }
    };

    const handleDeletePlan = async () => {
        if (!curriculum?.id || !isSaved) return;
        if (confirm("Bu eğitim planını kalıcı olarak silmek istediğinize emin misiniz?")) {
            setLoading(true);
            try {
                await curriculumService.deleteCurriculum(curriculum.id);
                setCurriculum(null);
                setStep(0);
                alert("Plan silindi.");
            } catch (e) {
                alert("Silme hatası.");
            } finally {
                setLoading(false);
            }
        }
    };

    const handlePrint = async (action: 'print' | 'download') => {
        setIsPrinting(true);
        setTimeout(async () => {
            try {
                await printService.generatePdf('.curriculum-plan-content', `${formData.name}-EgitimPlani`, { action });
            } catch (e) {
                console.error(e);
            } finally {
                setIsPrinting(false);
            }
        }, 100);
    };

    const handleToggleActivity = async (day: number, actId: string) => {
        if (!curriculum) return;
        const dayData = curriculum.schedule.find(d => d.day === day);
        const currentStatus = dayData?.activities.find(a => a.id === actId)?.status;
        const newStatus = currentStatus === 'completed' ? 'pending' : 'completed';

        try {
            if (isSaved) await curriculumService.updateActivityStatus(curriculum.id, day, actId, newStatus as any);
            setCurriculum(prev => {
                if (!prev) return null;
                return {
                    ...prev,
                    schedule: prev.schedule.map(d => {
                        if (d.day === day) {
                            const newActs = d.activities.map(a => a.id === actId ? { ...a, status: newStatus as any } : a);
                            return { ...d, activities: newActs, isCompleted: newActs.every(a => a.status === 'completed') };
                        }
                        return d;
                    })
                };
            });
        } catch (e) { alert("Durum güncellenemedi."); }
    };

    const handleSaveDayNote = async (dayNum: number, note: string) => {
        if (!curriculum || !isSaved) return;
        const newSchedule = curriculum.schedule.map(d => d.day === dayNum ? { ...d, focus: note } : d);
        setCurriculum({ ...curriculum, schedule: newSchedule });
        await curriculumService.updateCurriculum(curriculum.id, { schedule: newSchedule });
    };

    const renderWizard = () => {
        if (loading) {
            return (
                <div className="flex flex-col items-center justify-center py-20">
                    <div className="w-24 h-24 relative mb-8">
                        <div className="absolute inset-0 border-8 border-indigo-100 rounded-full"></div>
                        <div className="absolute inset-0 border-8 border-indigo-600 rounded-full border-t-transparent animate-spin"></div>
                        <div className="absolute inset-0 flex items-center justify-center text-indigo-600">
                            <i className="fa-solid fa-wand-magic-sparkles text-3xl"></i>
                        </div>
                    </div>
                    <h3 className="text-2xl font-black text-zinc-800 dark:text-white mb-2 text-center">Nöro-Pedagogik Analiz Yapılıyor...</h3>
                    <p className="text-zinc-500 text-center max-w-sm">AI, öğrencinin zayıf yönlerini sarmal öğrenme modeliyle {planDuration} günlük bir rotaya dönüştürüyor.</p>
                </div>
            );
        }

        switch(step) {
            case 0:
                return (
                    <div className="max-w-2xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4">
                        <div className="text-center">
                            <div className="w-20 h-20 bg-indigo-100 dark:bg-indigo-900/30 text-indigo-600 rounded-3xl flex items-center justify-center text-3xl mx-auto mb-6 shadow-lg shadow-indigo-500/20">
                                <i className="fa-solid fa-graduation-cap"></i>
                            </div>
                            <h2 className="text-4xl font-black text-zinc-900 dark:text-white tracking-tight mb-4">Eğitim Planlayıcı</h2>
                            <p className="text-zinc-500">Mevcut bir öğrenciyi atayın veya yeni bir profil ile başlayın.</p>
                        </div>
                        <div className="bg-white dark:bg-zinc-800 p-8 rounded-[2.5rem] border border-zinc-200 dark:border-zinc-700 shadow-xl space-y-6">

                            <div className="p-5 bg-amber-50 dark:bg-amber-900/10 rounded-2xl border border-amber-100 dark:border-amber-800/30">
                                <label className="block text-[10px] font-black text-amber-600 dark:text-amber-500 uppercase tracking-widest mb-3 flex items-center gap-2">
                                    <i className="fa-solid fa-user-check"></i> Mevcut Öğrenci Atama
                                </label>
                                <select 
                                    value={formData.id || 'new'} 
                                    onChange={e => handleStudentSelect(e.target.value)}
                                    className="w-full p-3 bg-white dark:bg-zinc-900 border border-amber-200 dark:border-amber-700 rounded-xl font-bold text-sm outline-none cursor-pointer focus:ring-2 ring-amber-500/20"
                                >
                                    <option value="new">-- Yeni Profil Oluştur --</option>
                                    {students.map(s => <option key={s.id} value={s.id}>{s.name} ({s.grade})</option>)}
                                </select>
                            </div>

                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-xs font-black text-zinc-400 uppercase tracking-widest mb-2">Öğrenci Adı</label>
                                    <input 
                                        type="text" 
                                        value={formData.name} 
                                        onChange={e => setFormData({...formData, name: e.target.value})}
                                        className="w-full p-4 bg-zinc-50 dark:bg-zinc-900 border border-zinc-200 dark:border-zinc-700 rounded-2xl font-bold focus:ring-2 focus:ring-indigo-500 outline-none" 
                                        placeholder="Ad Soyad"
                                    />
                                </div>
                                <div>
                                    <label className="block text-xs font-black text-zinc-400 uppercase tracking-widest mb-2">Sınıf</label>
                                    <select value={formData.grade} onChange={e => setFormData({...formData, grade: e.target.value})} className="w-full p-4 bg-zinc-50 dark:bg-zinc-900 border border-zinc-200 dark:border-zinc-700 rounded-2xl font-bold outline-none">
                                        {['Okul Öncesi', '1. Sınıf', '2. Sınıf', '3. Sınıf', '4. Sınıf', '5. Sınıf', '6. Sınıf', '7. Sınıf', '8. Sınıf'].map(g => <option key={g} value={g}>{g}</option>)}
                                    </select>
                                </div>
                            </div>

                            <div>
                                <label className="block text-xs font-black text-zinc-400 uppercase tracking-widest mb-2">Plan Süresi</label>
                                <div className="grid grid-cols-3 gap-3">
                                    {[7, 15, 30].map(d => (
                                        <button 
                                            key={d}
                                            onClick={() => setPlanDuration(d)}
                                            className={`py-3 rounded-xl font-bold text-sm transition-all border-2 ${planDuration === d ? 'bg-indigo-600 text-white border-indigo-600 shadow-md' : 'bg-white dark:bg-zinc-700 text-zinc-500 border-zinc-100 dark:border-zinc-600'}`}
                                        >
                                            {d} GÜN
                                        </button>
                                    ))}
                                </div>
                            </div>

                            <button onClick={() => setStep(1)} disabled={!formData.name} className="w-full py-4 bg-zinc-900 dark:bg-white text-white dark:text-black font-black rounded-2xl shadow-lg transition-all active:scale-95 disabled:opacity-50 uppercase tracking-widest">DEVAM ET <i className="fa-solid fa-chevron-right ml-2"></i></button>
                        </div>
                    </div>
                );
            case 1:
                return (
                    <div className="max-w-2xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4">
                        <div className="text-center">
                            <h2 className="text-3xl font-black text-zinc-900 dark:text-white">Akademik Profil Özeti</h2>
                            <p className="text-zinc-500">Bu veriler AI'nın her güne özel zorluk seviyesi belirlemesi için kullanılacaktır.</p>
                        </div>

                        {/* DIAGNOSIS CONTEXT DISPLAY */}
                        {diagnosisContext && (
                            <div className="bg-indigo-50 dark:bg-indigo-900/10 p-6 rounded-2xl border border-indigo-100 dark:border-indigo-800">
                                <h4 className="text-[10px] font-black text-indigo-600 dark:text-indigo-400 uppercase tracking-widest mb-2 flex items-center gap-2">
                                    <i className="fa-solid fa-clipboard-check"></i> KLİNİK TARAMA BULGULARI
                                </h4>
                                <p className="text-sm text-zinc-700 dark:text-zinc-300 italic leading-relaxed whitespace-pre-line">
                                    {diagnosisContext}
                                </p>
                            </div>
                        )}

                        <div className="bg-white dark:bg-zinc-800 p-8 rounded-[2.5rem] border border-zinc-200 dark:border-zinc-700 shadow-xl space-y-6">
                            <div>
                                <label className="block text-xs font-black text-zinc-400 uppercase tracking-widest mb-3">Öğrencinin İlgi Alanları (AI Teması)</label>
                                <div className="flex flex-wrap gap-2">
                                    {['Uzay', 'Dinozorlar', 'Hayvanlar', 'Doğa', 'Spor', 'Müzik', 'Robotlar', 'Denizler'].map(tag => (
                                        <button 
                                            key={tag}
                                            onClick={() => setFormData(prev => ({ ...prev, interests: prev.interests?.includes(tag) ? prev.interests.filter(t => t !== tag) : [...(prev.interests || []), tag] }))}
                                            className={`px-4 py-2 rounded-xl font-bold text-xs border-2 transition-all ${formData.interests?.includes(tag) ? 'bg-indigo-600 text-white border-indigo-600' : 'bg-white dark:bg-zinc-700 text-zinc-500 border-zinc-100 dark:border-zinc-600'}`}
                                        >
                                            {tag}
                                        </button>
                                    ))}
                                </div>
                            </div>

                            <div>
                                <label className="block text-xs font-black text-zinc-400 uppercase tracking-widest mb-3">Klinik Hedefler (Zayıf Yönler)</label>
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                                    {/* Pre-fill logic might already populate some, allow user to add more */}
                                    {[
                                        'Harf Karıştırma', 'Yavaş Okuma', 'Sayı Hissi', 'Dikkat Dağınıklığı', 'Sıralama Sorunları', 'Ters Yazma',
                                        // Dynamic entries from screening if not in static list
                                        ...(formData.weaknesses || []).filter(w => !['Harf Karıştırma', 'Yavaş Okuma', 'Sayı Hissi', 'Dikkat Dağınıklığı', 'Sıralama Sorunları', 'Ters Yazma'].includes(w))
                                    ].map(item => (
                                        <label key={item} className={`flex items-center gap-3 p-4 rounded-2xl border-2 transition-all cursor-pointer ${formData.weaknesses?.includes(item) ? 'bg-rose-50 border-rose-400 dark:bg-rose-900/20' : 'bg-white dark:bg-zinc-800 border-zinc-100 dark:border-zinc-700'}`}>
                                            <input type="checkbox" checked={formData.weaknesses?.includes(item)} onChange={() => setFormData(prev => ({ ...prev, weaknesses: prev.weaknesses?.includes(item) ? prev.weaknesses.filter(t => t !== item) : [...(prev.weaknesses || []), item] }))} className="hidden" />
                                            <div className={`w-5 h-5 rounded-full border-2 flex items-center justify-center ${formData.weaknesses?.includes(item) ? 'bg-rose-500 border-rose-500 text-white' : 'border-zinc-300'}`}><i className="fa-solid fa-check text-[10px]"></i></div>
                                            <span className="font-bold text-sm">{item}</span>
                                        </label>
                                    ))}
                                </div>
                            </div>

                            <div className="flex justify-between items-center pt-4">
                                <button onClick={() => setStep(0)} className="text-sm font-bold text-zinc-400 hover:text-zinc-600"><i className="fa-solid fa-arrow-left mr-2"></i> Geri Dön</button>
                                <button onClick={handleGenerate} className="px-10 py-4 bg-indigo-600 text-white font-black rounded-2xl shadow-xl hover:scale-105 transition-all">PROGRAMI İNŞA ET <i className="fa-solid fa-wand-magic-sparkles ml-2"></i></button>
                            </div>
                        </div>
                    </div>
                );
            case 4:
                return (
                    <div className="curriculum-plan-content max-w-5xl mx-auto space-y-10 pb-20">
                        {curriculum && (
                            <>
                                <div className="bg-white dark:bg-zinc-800 rounded-[2.5rem] p-10 border border-zinc-200 dark:border-zinc-700 shadow-xl relative overflow-hidden print:border-none print:shadow-none">
                                    <div className="absolute top-0 right-0 w-64 h-64 bg-indigo-500/5 rounded-full blur-3xl -translate-y-1/2 translate-x-1/2 print:hidden"></div>
                                    <div className="relative z-10">
                                        <div className="flex flex-col md:flex-row justify-between items-start mb-8 gap-6">
                                            <div className="flex gap-6 items-center">
                                                <div className="w-20 h-20 rounded-[2rem] bg-indigo-600 text-white flex items-center justify-center text-3xl shadow-xl border-4 border-white dark:border-zinc-700">
                                                    <i className="fa-solid fa-graduation-cap"></i>
                                                </div>
                                                <div>
                                                    <span className="px-3 py-1 bg-indigo-100 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-400 rounded-full text-[10px] font-black uppercase tracking-widest border border-indigo-200 dark:border-indigo-800">Bireysel Gelişim Rotası</span>
                                                    <h1 className="text-4xl font-black text-zinc-900 dark:text-white mt-2 tracking-tight">{curriculum.studentName}</h1>
                                                    <p className="text-zinc-500 font-bold mt-1 uppercase text-xs tracking-widest">{curriculum.grade} • {curriculum.durationDays} GÜNLÜK AKIŞ</p>
                                                </div>
                                            </div>
                                            <div className="flex flex-col items-end gap-3">
                                                <div className="bg-zinc-50 dark:bg-zinc-900 p-4 rounded-2xl border border-zinc-100 dark:border-zinc-800 flex flex-col items-center">
                                                    <p className="text-[9px] font-black text-zinc-400 uppercase tracking-widest mb-1">GENEL İLERLEME</p>
                                                    <span className="text-2xl font-black text-indigo-600">%{Math.round((curriculum.schedule.filter(d => d.isCompleted).length / curriculum.schedule.length) * 100)}</span>
                                                </div>
                                                {isSaved && (
                                                    <button onClick={handleDeletePlan} className="text-xs font-bold text-red-400 hover:text-red-500 transition-colors uppercase tracking-widest flex items-center gap-2 px-2">
                                                        <i className="fa-solid fa-trash-can"></i> Planı Sil
                                                    </button>
                                                )}
                                            </div>
                                        </div>
                                        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                                            <div className="space-y-4">
                                                <h4 className="text-[10px] font-black text-zinc-400 uppercase tracking-widest border-b pb-2">Plan Hedefleri</h4>
                                                <div className="space-y-2">
                                                    {curriculum.goals.map((g, i) => (
                                                        <div key={i} className="flex gap-3 items-center text-sm font-bold text-zinc-700 dark:text-zinc-300">
                                                            <div className="w-1.5 h-1.5 rounded-full bg-indigo-500"></div> {g}
                                                        </div>
                                                    ))}
                                                </div>
                                            </div>
                                            <div className="p-6 bg-zinc-50 dark:bg-zinc-900/50 rounded-3xl border border-zinc-100 dark:border-zinc-800 italic text-sm text-zinc-600 dark:text-zinc-400 leading-relaxed shadow-inner">
                                                <i className="fa-solid fa-quote-left text-indigo-300 dark:text-indigo-700 mb-2 block"></i> "{curriculum.note}"
                                            </div>
                                        </div>
                                    </div>
                                </div>
                                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                                    {curriculum.schedule.map((day, idx) => {
                                        const isFirstIncomplete = !day.isCompleted && (idx === 0 || curriculum.schedule[idx-1].isCompleted);
                                        return (
                                            <DayCard 
                                                key={day.day} 
                                                day={day} 
                                                isActiveDay={isFirstIncomplete}
                                                onToggleActivity={handleToggleActivity} 
                                                onStartActivity={(id, type, title, diff, goal) => onStartCurriculumActivity(curriculum.id, day.day, id, type, curriculum.studentName, title, diff, goal, curriculum.studentId || undefined)} 
                                                onSaveNote={handleSaveDayNote}
                                            />
                                        );
                                    })}
                                </div>
                            </>
                        )}
                    </div>
                );
            default: return null;
        }
    };

    return (
        <div className="h-full bg-zinc-50 dark:bg-zinc-900 flex flex-col overflow-hidden relative absolute inset-0 z-50">
            <div className="h-16 border-b border-zinc-200 dark:border-zinc-800 bg-white dark:bg-zinc-800 flex justify-between items-center px-6 shadow-sm shrink-0 z-20 print:hidden">
                <div className="flex items-center gap-4">
                    <button onClick={onBack} className="w-10 h-10 rounded-xl hover:bg-zinc-100 dark:hover:bg-zinc-700 flex items-center justify-center transition-colors text-zinc-500">
                        <i className="fa-solid fa-arrow-left"></i>
                    </button>
                    <h2 className="text-lg font-black text-zinc-800 dark:text-white flex items-center gap-2">
                        <i className="fa-solid fa-calendar-check text-indigo-500"></i> Akıllı Müfredat Stüdyosu
                    </h2>
                </div>
                <div className="flex gap-3">
                    {step === 4 && curriculum && (
                        <>
                            <button onClick={() => setIsShareModalOpen(true)} className="w-10 h-10 rounded-xl hover:bg-zinc-100 dark:hover:bg-zinc-700 flex items-center justify-center text-zinc-500 transition-colors" title="Paylaş"><i className="fa-solid fa-share-nodes"></i></button>
                            <button onClick={() => handlePrint('download')} disabled={isPrinting} className="w-10 h-10 rounded-xl bg-zinc-800 hover:bg-zinc-700 flex items-center justify-center text-zinc-500 transition-colors">{isPrinting ? <i className="fa-solid fa-circle-notch fa-spin"></i> : <i className="fa-solid fa-file-pdf"></i>}</button>
                            <button onClick={() => handlePrint('print')} disabled={isPrinting} className="w-10 h-10 rounded-xl bg-zinc-800 hover:bg-zinc-700 flex items-center justify-center text-zinc-500 transition-colors"><i className="fa-solid fa-print"></i></button>
                            <button onClick={handleSave} disabled={isSaved || isSaving} className={`px-6 py-2 rounded-xl text-xs font-black transition-all flex items-center gap-2 shadow-lg ${isSaved ? 'bg-emerald-600 text-white cursor-default' : 'bg-zinc-900 text-white hover:bg-black dark:bg-white dark:text-black dark:hover:bg-zinc-200'}`}>
                                {isSaving ? <i className="fa-solid fa-circle-notch fa-spin"></i> : isSaved ? <><i className="fa-solid fa-check"></i> Plan Kaydedildi</> : <><i className="fa-solid fa-save"></i> Planı Arşivle</>}
                            </button>
