            <button 
                onClick={() => onLoad(item)} 
                className="text-xs font-bold text-indigo-600 hover:text-indigo-800 dark:text-indigo-400 dark:hover:text-indigo-300 hover:underline flex items-center gap-2"
            >
                <i className="fa-solid fa-eye"></i> Raporu Aç
